{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom/item_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdom\n      # デバイスファクトリー(1D6)\n      def mk_device_factory_table()\n        output = mk_item_decide_table(@randomizer.roll_once(6))\n\n        dice = @randomizer.roll_sum(2, 6)\n        output = output + \" / \" + mk_item_features_table(dice)\n        return output\n      end\n\n      # アイテムカテゴリ決定表(1D6)\n      def mk_item_decide_table(num)\n        functionTable = [\n          [1, lambda { mk_weapon_item_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [2, lambda { mk_life_item_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [3, lambda { mk_rest_item_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [4, lambda { mk_search_item_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [5, lambda { mk_rare_weapon_item_table(@randomizer.roll_d66(D66SortType::NO_SORT)) }],\n          [6, lambda { mk_rare_item_table(@randomizer.roll_d66(D66SortType::NO_SORT)) }],\n        ]\n        return get_table_by_number(num, functionTable)\n      end\n\n      # 武具アイテム表(D66)\n      def mk_weapon_item_table(num)\n        table = [\n          [11, \"だんびら\"],\n          [12, \"だんびら\"],\n          [13, \"ダガー\"],\n          [14, \"戦斧\"],\n          [15, \"盾\"],\n          [16, \"鑓\"],\n          [22, \"籠手（だんびら）\"],\n          [23, \"手裏剣\"],\n          [24, \"石弓\"],\n          [25, \"甲冑\"],\n          [26, \"戦鎚\"],\n          [33, \"大弓（だんびら）\"],\n          [34, \"爆弾\"],\n          [35, \"鉄砲\"],\n          [36, \"大剣\"],\n          [44, \"拳銃（だんびら）\"],\n          [45, \"ホウキ\"],\n          [46, \"徹甲弾\"],\n          [55, \"だんびら\"],\n          [56, \"大砲\"],\n          [66, \"だんびら\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # 生活アイテム表(D66)\n      def mk_life_item_table(num)\n        table = [\n          [11, \"バックパック\"],\n          [12, \"バックパック\"],\n          [13, \"鍋\"],\n          [14, \"クラッカー\"],\n          [15, \"がまぐち\"],\n          [16, \"マント\"],\n          [22, \"法衣（バックパック）\"],\n          [23, \"カード\"],\n          [24, \"エプロン\"],\n          [25, \"住民台帳\"],\n          [26, \"携帯電話\"],\n          [33, \"召喚鍵（バックパック）\"],\n          [34, \"肖像画\"],\n          [35, \"衣装\"],\n          [36, \"山吹色のお菓子\"],\n          [44, \"バックパック\"],\n          [45, \"眼鏡\"],\n          [46, \"クレジットカード\"],\n          [55, \"バックパック\"],\n          [56, \"魔道書\"],\n          [66, \"バックパック\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # 回復アイテム表(D66)\n      def mk_rest_item_table(num)\n        table = [\n          [11, \"お弁当\"],\n          [12, \"お弁当\"],\n          [13, \"特効薬\"],\n          [14, \"保存食\"],\n          [15, \"担架\"],\n          [16, \"珈琲\"],\n          [22, \"軟膏（お弁当）\"],\n          [23, \"チョコレート\"],\n          [24, \"お酒\"],\n          [25, \"フルコース\"],\n          [26, \"ポーション\"],\n          [33, \"お弁当\"],\n          [34, \"救急箱\"],\n          [35, \"強壮剤\"],\n          [36, \"迷宮保険\"],\n          [44, \"お弁当\"],\n          [45, \"科学調味料\"],\n          [46, \"惚れ薬\"],\n          [55, \"お弁当\"],\n          [56, \"復活薬\"],\n          [66, \"お弁当\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # 探索アイテム表(D66)\n      def mk_search_item_table(num)\n        table = [\n          [11, \"星の欠片\"],\n          [12, \"星の欠片\"],\n          [13, \"旗\"],\n          [14, \"お守り\"],\n          [15, \"拷問具\"],\n          [16, \"パワーリスト\"],\n          [22, \"工具（星の欠片）\"],\n          [23, \"テント\"],\n          [24, \"楽器\"],\n          [25, \"使い魔\"],\n          [26, \"乗騎\"],\n          [33, \"迷宮迷彩（星の欠片）\"],\n          [34, \"罠百科\"],\n          [35, \"迷宮防護服\"],\n          [36, \"地図\"],\n          [44, \"星の欠片\"],\n          [45, \"時計\"],\n          [46, \"もぐら棒\"],\n          [55, \"星の欠片\"],\n          [56, \"カボチャの馬車\"],\n          [66, \"星の欠片\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # レア武具アイテム表(1D6+1D6)\n      def mk_rare_weapon_item_table(num)\n        table = [\n          [11, \"虚弾\"],\n          [12, \"怪物毒\"],\n          [13, \"小鬼の襟巻\"],\n          [14, \"喇叭銃\"],\n          [15, \"蛍矢\"],\n          [16, \"大盾\"],\n          [21, \"まわし\"],\n          [22, \"怪物毒\"],\n          [23, \"しゃべる剣\"],\n          [24, \"小麦粉\"],\n          [25, \"王笏\"],\n          [26, \"服従の鞭\"],\n          [31, \"ぬいぐるみ\"],\n          [32, \"魔杖\"],\n          [33, \"怪物毒\"],\n          [34, \"星衣\"],\n          [35, \"聖印\"],\n          [36, \"獣の毛皮\"],\n          [41, \"日傘\"],\n          [42, \"チェインソード\"],\n          [43, \"邪眼\"],\n          [44, \"怪物毒\"],\n          [45, \"徒手空拳\"],\n          [46, \"バカには見えない鎧\"],\n          [51, \"ビキニアーマー\"],\n          [52, \"輝く者\"],\n          [53, \"貪る者\"],\n          [54, \"滅ぼす者\"],\n          [55, \"機械の体\"],\n          [56, \"破城槌\"],\n          [61, \"刈り取る者\"],\n          [62, \"貫く者\"],\n          [63, \"黄金の鶴嘴\"],\n          [64, \"ムラサマ\"],\n          [65, \"蒸気甲冑\"],\n          [66, \"王剣\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # レア一般アイテム表(1D6+1D6)\n      def mk_rare_item_table(num)\n        table = [\n          [11, \"ブルーリボン\"],\n          [12, \"聖痕\"],\n          [13, \"剥製\"],\n          [14, \"愚者の冠\"],\n          [15, \"名刺\"],\n          [16, \"種籾\"],\n          [21, \"香水\"],\n          [22, \"守りの指輪（名刺）\"],\n          [23, \"煙玉\"],\n          [24, \"悪名\"],\n          [25, \"藁人形\"],\n          [26, \"パワー餌\"],\n          [31, \"王妃の鏡\"],\n          [32, \"蓄音機\"],\n          [33, \"無限の心臓（名刺）\"],\n          [34, \"星籠\"],\n          [35, \"水晶球\"],\n          [36, \"転ばぬ先の杖\"],\n          [41, \"悟りの書\"],\n          [42, \"操りロープ\"],\n          [43, \"盗賊の七つ道具\"],\n          [44, \"携帯算術機（名刺）\"],\n          [45, \"棺桶\"],\n          [46, \"カメラ\"],\n          [51, \"不思議なたまご\"],\n          [52, \"ブーケ\"],\n          [53, \"露眼鏡\"],\n          [54, \"災厄王の遺物\"],\n          [55, \"経験値\"],\n          [56, \"鞍\"],\n          [61, \"視肉\"],\n          [62, \"玉璽\"],\n          [63, \"衛星帯\"],\n          [64, \"軍配\"],\n          [65, \"聖杯\"],\n          [66, \"愛\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # アイテムの特性決定表(2D6)\n      def mk_item_features_table(num)\n        output = \"\"\n        dice = @randomizer.roll_sum(2, 6)\n\n        if num <= 2\n          output = \"「\" + mk_item_power_table(@randomizer.roll_once(6)) + \"」の神力を宿す\"\n        elsif num <= 3\n          output = \"寿命を持つ。寿命の値を決定する。\" + \"\\n\"\n          output += \"さらに、\" + mk_item_features_table(dice)\n        elsif num <= 4\n          output = \"境界障壁を持つ。《HP》の値を決定する。\"\n        elsif num <= 5\n          output = \"銘を持つ。銘を決定する。\"\n        elsif num <= 6\n          output = \"合成具である。もう1つの機能は「\" + mk_item_decide_table(@randomizer.roll_once(6)) + \"」である。\"\n        elsif num <= 7\n          output = \"そのアイテムにレベルがあれば、レベルを1点上昇する。\" + \"\\n\"\n          output += \"レベルが設定されていなければ、\" + mk_item_features_table(dice)\n        elsif num <= 8\n          output = \"「\" + mk_item_jyumon_table(dice) + \"」の呪紋を持つ。\"\n        elsif num <= 9\n          output = \"「\" + mk_item_jyuka_table(@randomizer.roll_once(6)) + \"」の呪禍を持つ。\" + \"\\n\"\n          output += \"さらに、\" + mk_item_features_table(dice)\n        elsif num <= 10\n          output = \"高価だ。価格を設定する。\"\n        elsif num <= 11\n          output = \"「条件：\" + mk_item_aptitude_table(@randomizer.roll_once(6)) + \"」の適性を持つ。\" + \"\\n\"\n          output += \"さらに、\" + mk_item_features_table(dice)\n        else\n          output = \"「\" + mk_item_attribute_table(@randomizer.roll_once(6)) + \"」の属性を持つ。\"\n        end\n\n        return \"特性[\" + num.to_s + \"]：\" + output\n      end\n\n      # 神力決定表(1D6)\n      def mk_item_power_table(num)\n        table = [\n          [1, \"〔才覚〕\"],\n          [2, \"〔魅力〕\"],\n          [3, \"〔探索〕\"],\n          [4, \"〔武勇〕\"],\n          [5, \"〈器〉\"],\n          [6, \"〈回避値〉\"],\n        ]\n\n        return \"[\#{num}]\" + get_table_by_number(num, table)\n      end\n\n      # 呪紋決定表(2D6)\n      def mk_item_jyumon_table(num)\n        table = [\n          [2, \"モンスタースキル\"],\n          [3, \"便利スキル\"],\n          [4, \"芸能スキル\"],\n          [5, \"迷宮スキル\"],\n          [6, \"星術スキル\"],\n          [7, \"一般スキル\"],\n          [8, \"召喚スキル\"],\n          [9, \"科学スキル\"],\n          [10, \"交渉スキル\"],\n          [11, \"神官のクラススキル\"],\n          [12, \"ジョブスキル\"],\n        ]\n\n        return \"[\#{num}]\" + get_table_by_number(num, table)\n      end\n\n      # 呪禍表(1D6)\n      def mk_item_jyuka_table(num)\n        table = [\n          [1, \"「呪い」のバッドステータス\"],\n          [2, \"「肥満」のバッドステータス\"],\n          [3, \"「愚か」のバッドステータス\"],\n          [4, \"サイクルの終了時に《HP》が1点減少する\"],\n          [5, \"条件を満たしても誰とも人間関係を結べない\"],\n          [6, \"〈器〉が1点減少する\"],\n        ]\n\n        return \"[\#{num}]\" + get_table_by_number(num, table)\n      end\n\n      # 適正表(1D6)\n      def mk_item_aptitude_table(num)\n        table = [\n          [1, \"ランダムなクラス1種\"],\n          [2, lambda { mk_family_business_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [3, lambda { mk_gender_table(@randomizer.roll_once(6)) + \"性\" }],\n          [4, \"上級ジョブ\"],\n          [5, \"モンスタースキルを修得\"],\n          [6, \"童貞、もしくは処女\"],\n        ]\n\n        return \"[\#{num}]\" + get_table_by_number(num, table)\n      end\n\n      # 属性表(1D6)\n      def mk_item_attribute_table(num)\n        table = [\n          [1, \"自然の力\"],\n          [2, \"幻夢の力\"],\n          [3, \"星炎の力\"],\n          [4, \"暗黒の力\"],\n          [5, \"聖なるの力\"],\n          [6, \"災厄の力\"],\n        ]\n\n        return \"[\#{num}]\" + get_table_by_number(num, table)\n      end\n\n      def mk_gender_table(num)\n        output = \"1\"\n\n        if num.odd?\n          output = \"男\"\n        else\n          output = \"女\"\n        end\n\n        return output\n      end\n\n      # 生まれ表(D66)\n      def mk_family_business_table(num)\n        table = [\n          [11, \"星術師\"],\n          [12, \"魔道師\"],\n          [13, \"召喚師\"],\n          [14, \"博士\"],\n          [15, \"医者\"],\n          [16, \"貴族\"],\n          [22, \"宦官\"],\n          [23, \"武人\"],\n          [24, \"処刑人\"],\n          [25, \"衛視\"],\n          [26, \"商人\"],\n          [33, \"迷宮職人\"],\n          [34, \"亭主\"],\n          [35, \"料理人\"],\n          [36, \"寿ぎ屋\"],\n          [44, \"働きもの\"],\n          [45, \"狩人\"],\n          [46, \"冒険者\"],\n          [55, \"怠け者\"],\n          [56, \"盗賊\"],\n          [66, \"生まれ表の中から、好きなジョブ1つを選ぶ\"],\n        ]\n\n        return \"[\#{num}]\" + get_table_by_number(num, table)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdom>", "mk_device_factory_table", "output", "self", "mk_item_decide_table", "@randomizer", "roll_once", "6", "dice", "roll_sum", "2", "+", "mk_item_features_table", "num", "functionTable", "1", "lambda", "block in mk_item_decide_table", "block (2 levels) in mk_item_decide_table", "mk_weapon_item_table", "roll_d66", "D66SortType::ASC", "D66SortType", "mk_life_item_table", "3", "mk_rest_item_table", "4", "mk_search_item_table", "5", "mk_rare_weapon_item_table", "D66SortType::NO_SORT", "mk_rare_item_table", "get_table_by_number", "table", "11", "12", "13", "14", "15", "16", "22", "23", "24", "25", "26", "33", "34", "35", "36", "44", "45", "46", "55", "56", "66", "21", "31", "32", "41", "42", "43", "51", "52", "53", "54", "61", "62", "63", "64", "65", "<=", "mk_item_power_table", "7", "8", "mk_item_jyumon_table", "9", "mk_item_jyuka_table", "10", "mk_item_aptitude_table", "mk_item_attribute_table", "to_s", "block in mk_item_aptitude_table", "block (2 levels) in mk_item_aptitude_table", "mk_family_business_table", "mk_gender_table", "odd?"], :mappings=>"AAAAA,+DAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAA