（ネオ）\"],\n          [24, \"神聖（セント、聖）\"],\n          [25, \"正統\"],\n          [26, \"絶対主義\"],\n          [33, \"大\"],\n          [34, \"天階\"],\n          [35, \"深階\"],\n          [36, \"第三\"],\n          [44, \"中央\"],\n          [45, \"帝政\"],\n          [46, \"統一\"],\n          [55, \"独立\"],\n          [56, \"東\"],\n          [66, \"立憲\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 王国名決定表２(D66)\n      def mk_kingdom_name_2_table(num)\n        table = [\n          [11, \"英雄\"],\n          [12, \"連合\"],\n          [13, \"グランドゼロ\"],\n          [14, \"迷宮（ダンジョン）\"],\n          [15, \"災厄\"],\n          [16, \"魔神（デーモン）\"],\n          [22, \"征服\"],\n          [23, \"中華\"],\n          [24, \"ドラゴン（龍）\"],\n          [25, \"猫\"],\n          [26, \"バナナ\"],\n          [33, \"ファンタジー\"],\n          [34, \"冒険\"],\n          [35, \"魔法（マジカル）\"],\n          [36, \"超人\"],\n          [44, \"無敵\"],\n          [45, \"路地裏\"],\n          [46, \"ローマ\"],\n          [55, \"（好きな単語表で決定）\"],\n          [56, \"（プレイ会場の地名　例：ネリマ）\"],\n          [66, \"（国王の名前。後で決定）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 王国名決定表３(D66)\n      def mk_kingdom_name_3_table(num)\n        table = [\n          [11, \"王国（キングダム）\"],\n          [12, \"王朝\"],\n          [13, \"会社（公社）\"],\n          [14, \"学園（学校）\"],\n          [15, \"合衆国\"],\n          [16, \"共同体\"],\n          [22, \"共和国\"],\n          [23, \"星\"],\n          [24, \"公国\"],\n          [25, \"市（街、シティ、ポリス）\"],\n          [26, \"自治国\"],\n          [33, \"植民地\"],\n          [34, \"帝国\"],\n          [35, \"同盟\"],\n          [36, \"首長国\"],\n          [44, \"幕府\"],\n          [45, \"領\"],\n          [46, \"村\"],\n          [55, \"横丁（亭）\"],\n          [56, \"ランド\"],\n          [66, \"連邦\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdom>", "mk_kingdom_