uB;QAxBTC,CAAAA;QA4BA3B,OAAA4B,uCAAAA,mCAA4B1B,GAA5B0B;AAAAA,UAAAA;;;UACEzB,QAAQ,CACN,CAACC,EAAD,EAAKwB,WAAL,CADM,EAEN,CAACvB,EAAD,EAAKuB,IAAL,CAFM,EAGN,CAACtB,EAAD,EAAKsB,QAAL,CAHM,EAIN,CAACrB,EAAD,EAAKqB,QAAL,CAJM,EAKN,CAACpB,EAAD,EAAKoB,KAAL,CALM,EAMN,CAACnB,EAAD,EAAKmB,KAAL,CANM,EAON,CAAClB,EAAD,EAAKkB,KAAL,CAPM,EAQN,CAACjB,EAAD,EAAKiB,GAAL,CARM,EASN,CAAChB,EAAD,EAAKgB,IAAL,CATM,EAUN,CAACf,EAAD,EAAKe,cAAL,CAVM,EAWN,CAACd,EAAD,EAAKc,KAAL,CAXM,EAYN,CAACb,EAAD,EAAKa,KAAL,CAZM,EAaN,CAACZ,EAAD,EAAKY,IAAL,CAbM,EAcN,CAACX,EAAD,EAAKW,IAAL,CAdM,EAeN,CAACV,EAAD,EAAKU,KAAL,CAfM,EAgBN,CAACT,EAAD,EAAKS,IAAL,CAhBM,EAiBN,CAACR,EAAD,EAAKQ,GAAL,CAjBM,EAkBN,CAACP,EAAD,EAAKO,GAAL,CAlBM,EAmBN,CAACN,EAAD,EAAKM,OAAL,CAnBM,EAoBN,CAACL,EAAD,EAAKK,KAAL,CApBM,EAqBN,CAACJ,EAAD,EAAKI,IAAL,CArBM;UAuBR,OAAOH,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QAxBTE,CAAAA;MA1DF5B,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>261, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom/landscape_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdom\n      # 迷宮風景決定表\n      def mk_ls_decide_table(num)\n        output = \"\"\n        num.times do |_i|\n          output += \"「\" + mk_landscape_table(@randomizer.roll_once(6)) + \"」\"\n        end\n        return output\n      end\n\n      # 迷宮風景表(1D6)\n      def mk_landscape_table(num)\n        dice = @randomizer.roll_d66(D66SortType::ASC)\n        table = [\n          [1, lambda { mk_artifact_landscape_table(dice) }],\n          [2, lambda { mk_cave_landscape_table(dice) }],\n          [3, lambda { mk_natural_landscape_table(dice) }],\n          [4, lambda { mk_waterside_landscape_table(dice) }],\n          [5, lambda { mk_skyrealm_landscape_table(dice) }],\n          [6, lambda { mk_strange_place_landscape_table(dice) }],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 人工風景表(D66)\n      def mk_artifact_landscape_table(num)\n        table = [\n          [11, \"石組みの部屋\"],\n          [12, \"巨大な縦穴に刻まれた螺旋階段\"],\n          [13, \"埃だらけの古い図書館\"],\n          [14, \"古びた、素朴な祭壇\"],\n          [15, \"歯車やピストンがやかましい動力室\"],\n          [16, \"石組みの巨大な階段\"],\n          [22, \"太い丸太で組まれた部屋\"],\n          [23, \"作りかけの製品が放置された工房\"],\n          [24, \"錆びた武器や骨が散らばる古戦場\"],\n          [25, \"石組みのトイレ\"],\n          [26, \"高い天井の厨房\"],\n          [33, \"レンガで組まれた部屋\"],\n          [34, \"静まりかえった劇場\"],\n          [35, \"がらくたが散らばっているゴミ捨て場\"],\n          [36, \"切り出し途中で放棄された巨大な石像\"],\n          [44, \"壁画やタペストリーが残る大広間\"],\n          [45, \"メトロ汗国の線路\"],\n          [46, \"絵画や彫刻が展示してあるギャラリー\"],\n          [55, \"石棺が並ぶ墓\"],\n          [56, \"錆びついた扉が残る巨大な門\"],\n          [66, \"放置された牢獄\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 洞窟風景表(D66)\n      def mk_cave_landscape_table(num)\n        table = [\n          [11, \"岩肌がむき出しの洞穴\"],\n          [12, \"コウモリや羽蟲が飛び交う洞穴\"],\n          [13, \"放置された坑道\"],\n          [14, \"誰かのキャンプ跡\"],\n          [15, \"岩だらけで見通しのきかない空洞\"],\n          [16, \"煙が吹きぬける洞穴\"],\n          [22, \"どこからか水音が響く鍾乳洞\"],\n          [23, \"光の衰えた星がまたたく幻想的な空洞\"],\n          [24, \"流砂が流れる洞穴\"],\n          [25, \"生物が掘った、つるつるした洞穴\"],\n          [26, \"冷えきった氷の洞穴\"],\n          [33, \"巨大な岩の隙間\"],\n          [34, \"動物や狩を描いた素朴な壁画が続く洞穴\"],\n          [35, \"巨大な空洞にかけられた自然の橋\"],\n          [36, \"埋まりかけで天井すれすれの洞穴\"],\n          [44, \"奈落と断崖絶壁\"],\n          [45, \"壁がうごめく蟲でおおわれた洞穴\"],\n          [46, \"無数の化石が埋まっている洞穴\"],\n          [55, \"熱気を放つ溶岩が流れる空洞\"],\n          [56, \"水晶でできた洞穴\"],\n          [66, \"骨が散らばるなにものかの住処\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 自然風景表(D66)\n      def mk_natural_landscape_table(num)\n        table = [\n          [11, \"苔むした部屋\"],\n          [12, \"動物の声が響き渡る密林\"],\n          [13, \"つる草でできた通路\"],\n          [14, \"空洞いっぱいのお花畑\"],\n          [15, \"壁から木の根が突き出している部屋\"],\n          [16, \"空洞に広がる耕作地\"],\n          [22, \"折り重なって繁茂する森林\"],\n          [23, \"垂直の空洞にえんえんと伸びる大木の幹\"],\n          [24, \"空洞中に広がるアザラシの営巣地\"],\n          [25, \"カビで壁がねとつく部屋\"],\n          [26, \"サボテンが点在する部屋\"],\n          [33, \"巨大キノコの群生地\"],\n          [34, \"真ん中に大木が一本そびえ立っている空洞\"],\n          [35, \"通路いっぱいに進む野生ウマトカゲの大群\"],\n          [36, \"落ち葉がうずたかく積もった部屋\"],\n          [44, \"植え込みで作られた迷宮庭園\"],\n          [45, \"生い茂る竹林\"],\n          [46, \"松ぼっくりが転がる部屋\"],\n          [55, \"丈の長い草が生い茂る部屋\"],\n          [56, \"枯れた森林\"],\n          [66, \"大木の空洞内のような通路や部屋\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 水域風景表(D66)\n      def mk_waterside_landscape_table(num)\n        table = [\n          [11, \"轟々と流れる川にかかった橋\"],\n          [12, \"色とりどりの珊瑚の中\"],\n          [13, \"腰高まで水に浸かった部屋\"],\n          [14, \"澄んだ水が流れる噴水と水飲み場\"],\n          [15, \"沸騰する湖\"],\n          [16, \"地面が干潟化した部屋\"],\n          [22, \"水をたたえた貯水池\"],\n          [23, \"熱い蒸気がたちこめる部屋\"],\n          [24, \"空洞に広がる沼地\"],\n          [25, \"樽や鎖が放置されている船の中\"],\n          [26, \"水槽が並ぶ水族館\"],\n          [33, \"悪臭を放つ下水道\"],\n          [34, \"底に遺跡が見える水没した空洞\"],\n          [35, \"桟橋と船着き場\"],\n          [36, \"筏やハシケが浮かぶ湖\"],\n          [44, \"巨大な縦穴と滝\"],\n          [45, \"かつて建設された上水道の中\"],\n          [46, \"ペンギンの右往左往する氷結した湖\"],\n          [55, \"湯気を立てる温泉\"],\n          [56, \"奇怪な彫刻が施された古井戸\"],\n          [66, \"壁に貝やフジツボがはりついた部屋\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 天空風景表(D66)\n      def mk_skyrealm_landscape_table(num)\n        table = [\n          [11, \"雨が降る部屋\"],\n          [12, \"チーズにうがたれた洞穴\"],\n          [13, \"中空に何層にも重なる空中庭園\"],\n          [14, \"無限に連なる真っ白な洗濯物\"],\n          [15, \"天空に向かって伸びる豆の木\"],\n          [16, \"巨大な縦穴にぶら下がる縄ばしごや鎖\"],\n          [22, \"強風の吹き荒れる部屋\"],\n          [23, \"雲の上。なぜか、その上を歩くことができる\"],\n          [24, \"濃霧に覆われた空洞\"],\n          [25, \"無重量でふわふわ浮く部屋\"],\n          [26, \"雪がしんしんと降り積もる部屋\"],\n          [33, \"時空がねじ曲がった空中回廊\"],\n          [34, \"怪物よけの風車が音を立てる通路\"],\n          [35, \"天井に遺跡が見える空洞\"],\n          [36, \"轟々と音を立てる巨大排気孔\"],\n          [44, \"時折稲妻の走る部屋\"],\n          [45, \"鳥の羽毛が舞い落ちる部屋\"],\n          [46, \"青空が壁面いっぱいに描かれた空洞\"],\n          [55, \"一面、鏡でできた部屋\"],\n          [56, \"オーロラがゆらめく空洞\"],\n          [66, \"重力方向がばらばらの部屋\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 異界風景表(D66)\n      def mk_strange_place_landscape_table(num)\n        table = [\n          [11, \"古びた六畳間\"],\n          [12, \"せせこましいカラオケボックス\"],\n          [13, \"時の止まった街\"],\n          [14, \"ボールが一個転がっている体育館\"],\n          [15, \"毛が生えている部屋\"],\n          [16, \"なにかの待合室\"],\n          [22, \"生物の粘液したたる体内\"],\n          [23, \"ブランコやすべり台のある小公園\"],\n          [24, \"安っぽいユニットバス\"],\n          [25, \"上の住人がうるさい部屋\"],\n          [26, \"人骨で組まれている部屋\"],\n          [33, \"呼吸している部屋\"],\n          [34, \"斜めに傾いた部屋\"],\n          [35, \"ラブホテルの一室\"],\n          [36, \"ときどきなにかが覗いていく部屋\"],\n          [44, \"がやがやと話し声が聞こえる部屋\"],\n          [45, \"触手が生えている部屋\"],\n          [46, \"机と椅子が置いてある取調室\"],\n          [55, \"静まりかえった教室\"],\n          [56, \"天井に巨大な人の顔がある部屋\"],\n          [66, \"常に揺れている部屋\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdom>", "mk_ls_decide_table", "num", "output", "times", "block in mk_ls_decide_table", "_i", "block (2 levels) in mk_ls_decide_table", "+", "self", "mk_landscape_table", "@randomizer", "roll_once", "6", "dice", "roll_d66", "D66SortType::ASC", "D66SortType", "table", "1", "lambda", "block in mk_landscape_table", "block (2 levels) in mk_landscape_table", "mk_artifact_landscape_table", "2", "mk_cave_landscape_table", "3", "mk_natural_landscape_table", "4", "mk_waterside_landscape_table", "5", "mk_skyrealm_landscape_table", "mk_strange_place_landscape_table", "get_table_by_number", "11", "12", "13", "14", "15", "