D,EAAKH,gBAAL,CAFM,EAGN,CAACI,EAAD,EAAKJ,SAAL,CAHM,EAIN,CAACK,EAAD,EAAKL,iBAAL,CAJM,EAKN,CAACM,EAAD,EAAKN,WAAL,CALM,EAMN,CAACO,EAAD,EAAKP,SAAL,CANM,EAON,CAACQ,EAAD,EAAKR,aAAL,CAPM,EAQN,CAACS,EAAD,EAAKT,iBAAL,CARM,EASN,CAACU,EAAD,EAAKV,YAAL,CATM,EAUN,CAACW,EAAD,EAAKX,aAAL,CAVM,EAWN,CAACY,EAAD,EAAKZ,aAAL,CAXM,EAYN,CAACa,EAAD,EAAKb,UAAL,CAZM,EAaN,CAACc,EAAD,EAAKd,UAAL,CAbM,EAcN,CAACe,EAAD,EAAKf,UAAL,CAdM,EAeN,CAACgB,EAAD,EAAKhB,iBAAL,CAfM,EAgBN,CAACiB,EAAD,EAAKjB,iBAAL,CAhBM,EAiBN,CAACkB,EAAD,EAAKlB,YAAL,CAjBM,EAkBN,CAACmB,EAAD,EAAKnB,eAAL,CAlBM,EAmBN,CAACoB,EAAD,EAAKpB,WAAL,CAnBM,EAoBN,CAACqB,EAAD,EAAKrB,gBAAL,CApBM,EAqBN,CAACsB,EAAD,EAAKtB,WAAL,CArBM;UAuBR,OAAOvB,IAAAwB,qBAAAA,CAAoB/B,GAApB,EAAyBgB,KAAzBe;QAxBTD,CAAAA;MArKFhC,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>368, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom/name_tables.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdom\n      # 名前表\n      def mk_name_table\n        debug(\"mk_name_table begin\")\n        output = \"1\"\n        # 名前表\n        name_n = @randomizer.roll_once(6)\n        debug(\"name_n\", name_n)\n\n        d1 = @randomizer.roll_d66(D66SortType::ASC)\n        d2 = @randomizer.roll_d66(D66SortType::ASC)\n        debug(\"d1, d2\", d1, d2)\n\n        debug(\"name_n\", name_n)\n        if name_n <= 1\n          # 名前表A＋二つ名表A\n          output = mk_nick_a_table(mk_name_a_table(d1), d2)\n        elsif name_n <= 2\n          # 名前表B＋二つ名表A\n          output = mk_nick_a_table(mk_name_b_table(d1), d2)\n        elsif name_n <= 3\n          # 名前表エキゾチック＋二つ名表A\n          output = mk_nick_a_table(mk_name_ex_table(d1), d2)\n        elsif name_n <= 4\n          # 名前表A＋二つ名表B\n          output = mk_nick_b_table(mk_name_a_table(d1), d2)\n        elsif name_n <= 5\n          # 名前表B＋二つ名表B\n          output = mk_nick_b_table(mk_name_b_table(d1), d2)\n        else\n          # 名前表ファンタジー＋二つ名表B\n          output = mk_nick_b_table(mk_name_fa_table(d1), d2)\n        end\n\n        dice = \"\#{name_n},\#{d1},\#{d2}\"\n\n        return output, dice\n      end\n\n      # 二つ名表A(D66)\n      def mk_nick_a_table(output, num)\n        table = [\n          [11, \"“災い転じて福となす”\"],\n          [12, \"“七転び八起きの”\"],\n          [13, \"“冗談にも程がある”\"],\n          [14, \"“虎の尾を踏む”\"],\n          [15, \"“石橋を叩いて渡る”\"],\n          [16, \"“一を聴いて十を知る”\"],\n          [22, \"“喉から手が出る”\"],\n          [23, \"“据え膳食わぬは男の恥の”\"],\n          [24, \"“天につば吐く”\"],\n          [25, \"“風に柳の”\"],\n          [26, \"“目に入れても痛くない”\"],\n          [33, \"“とかく浮世は色と酒の”\"],\n          [34, \"“当たるも八卦、当たらぬも八卦の”\"],\n          [35, \"“泣く子も黙る”\"],\n          [36, \"“天上天下唯我独尊”\"],\n          [44, \"“虫も殺さぬ”\"],\n          [45, \"“花も恥じらう”\"],\n          [46, \"“触らぬ神に祟り無しの”\"],\n          [55, \"“両手に花の”\"],\n          [56, \"“（ゲーム会場の地名）でも一、二を争う”\"],\n        ]\n        if num < 66\n          output = get_table_by_number(num, table) + output\n        else\n          output = \"\#{output}\#{@randomizer.roll_once(6)}世\"\n        end\n\n        return output\n      end\n\n      # 二つ名表B(D66)\n      def mk_nick_b_table(output, num)\n        table = [\n          [11, \"“身も蓋もない”\"],\n          [12, \"“七人の敵がいる”\"],\n          [13, \"“ドラゴンも裸足で逃げ出す”\"],\n          [14, \"“われらが”\"],\n          [15, \"“機会攻撃を誘発する”\"],\n          [16, \"“佳人薄命”\"],\n          [22, \"“すねに傷持つ”\"],\n          [23, \"“湯上りは親でも惚れる”\"],\n          [24, \"“叶わぬ時の神頼みの”\"],\n          [25, \"“果報は寝て待つ”\"],\n          [26, \"“清濁併せ呑む”\"],\n          [33, \"“かゆいところに手が届く”\"],\n          [34, \"“酒池肉林の”\"],\n          [35, \"“蛇の道は蛇の”\"],\n          [36, \"“口から先に生まれた”\"],\n          [44, \"“柔よく剛を制す”\"],\n          [45, \"“死人に口なしの”\"],\n          [46, \"“噂をすれば”\"],\n          [55, \"“ミスター／ミス”\"],\n          [56, \"“（好きな名前表）の子”\"],\n          [66, \"“（好きな単語表）の父／母”\"],\n        ]\n        return get_table_by_number(num, table) + output\n      end\n\n      # 名前表A(D66)\n      def mk_name_a_table(num)\n        table = [\n          [11, \"オレンジ／ジャスミン\"],\n          [12, \"ホオズキ／アサガオ\"],\n          [13, \"クローバー／ダチュラ\"],\n          [14, \"ダフニ／キノコ\"],\n          [15, \"グラナーダ／プリムローズ\"],\n          [16, \"ラディッシュ／マリーゴールド\"],\n          [22, \"サイプレス／マグノリア\"],\n          [23, \"バンブー／オリーブ\"],\n          [24, \"クラウド／クリマ\"],\n          [25, \"タオ／スノウ\"],\n          [26, \"アヴァランチ／エクレール\"],\n          [33, \"ビバシータ／メトロノーム\"],\n          [34, \"カノン／ファゴット\"],\n          [35, \"オーボエ／アルモニカ\"],\n          [36, \"チューバ／オルガノ\"],\n          [44, \"ナン／クッキー\"],\n          [45, \"ウイロウ／カシュカシュ\"],\n          [46, \"スコーン／クスクス\"],\n          [55, \"フラスコ／クリップ\"],\n          [56, \"クラパドーラ／クレヨン\"],\n          [66, \"ソープ／ブルーム\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # 名前表B(D66)\n      def mk_name_b_table(num)\n        table = [\n          [11, \"エイジ／ウェンズデイ\"],\n          [12, \"ジョルノ／ノエル\"],\n          [13, \"タスク／マニャーナ\"],\n          [14, \"ウィンター／ジュノー\"],\n          [15, \"ハイラン／ブランカ\"],\n          [16, \"ウォルナット／ルージュ\"],\n          [22, \"グレイ／スカーレット\"],\n          [23, \"シュバルツ／モエギ\"],\n          [24, \"スロット／キリエ\"],\n          [25, \"ジョーカー／ダイス\"],\n          [26, \"ジグソウ／ドミノ\"],\n          [33, \"バックギャモン／マーブル\"],\n          [34, \"シーガロ／ココア\"],\n          [35, \"スピーチカ／オレンジペコー\"],\n          [36, \"ジッポ／ショコラ\"],\n          [44, \"ナインピンズ／ルチャ\"],\n          [45, \"デカスロン／ラクロス\"],\n          [46, \"カバディ／ピンポン\"],\n          [55, \"ポンド／ヴェルベット\"],\n          [56, \"ルーブル／コットン\"],\n          [66, \"シリング／シルク\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n\n      # 名前表エキゾチック(D66)\n      def mk_name_ex_table(num)\n        table = [\n          [11, \"モアイ／スイショウドクロ\"],\n          [12, \"チュパカブラ／ムベンベ\"],\n          [13, \"カンフー／インヤン\"],\n          [14, \"ブシドー／ミヤコ\"],\n          [15, \"チャンピオン／バービー\"],\n          [16, \"ウパニシャッド／ゾルゲ\"],\n          [22, \"デスマーチ／インテル\"],\n          [23, \"ゴッホ／ヴィクトリア\"],\n          [24, \"ゾンビ／オニャンコポン\"],\n          [25, \"ゲロッパ／カルメン\"],\n          [26, \"オーバーキル／サシミ\"],\n          [33, \"ブッチャー／デヴィ\"],\n          [34, \"ブロンソン／マドンナ\"],\n          [35, \"ガイギャックス／エロイカ\"],\n          [36, \"好きな星の名前（スピカ,オリオン）\"],\n          [44, \"好きな武器の名前（エペ,フランベルジュ）\"],\n          [45, \"好きな動物の名前（イタチ,パグ）\"],\n          [46, \"好きな鉱物の名前（ルビィ,ヒスイ）\"],\n          [55, \"好きな言葉＋ドラゴン\"],\n          [56, \"好きな単語表で決定する\"],\n          [66, \"プレイヤーと同じ名前\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 名前表ファンタジー(D66)\n      def mk_name_fa_table(num)\n        table = [\n          [11, \"アダム／イヴ\"],\n          [12, \"ジャック／モモ\"],\n          [13, \"オズ／アリス\"],\n          [14, \"コナン／レダ\"],\n          [15, \"アーサー／イシス\"],\n          [16, \"エルリック／グローリアーナ\"],\n          [22, \"ギルガメッシュ／アマテラス\"],\n          [23, \"マハラジャ／クリシュナ\"],\n          [24, \"カゲオトコ／クロトカゲ\"],\n          [25, \"オルフェウス／ヴィーナス\"],\n          [26, \"ソロモン／サロメ\"],\n          [33, \"ワタリガラス／ディードリット\"],\n          [34, \"ニャルラトホテプ／バースト\"],\n          [35, \"アンナタール／フォルトゥナ\"],\n          [36, \"ザナドゥ／ヨミ\"],\n          [44, \"アルビオン／ラピュタ\"],\n          [45, \"ゼンダ／ゴーメンガースト\"],\n          [46, \"インスマウス／イース\"],\n          [55, \"フウヌイム／ヤプー\"],\n          [56, \"ザンス／ナルニア\"],\n          [66, \"カレワラ／イーハトーブ\"],\n        ]\n\n        return get_table_by_number(num, table)\n      end\n    end\n  end\nend\n\n# puts BCDice::GameSystem::MeikyuKingdom.new.methods.sort\n\n# exit 1\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdom>", "mk_name_table", "self", "debug", "output", "name_n", "@randomizer", "roll_once", "6", "d1", "roll_d66", "D66SortType::ASC", "D66SortType", "d2", "<=", "1", "mk_nick_a_table", "mk_name_a_table", "2", "mk_name_b_table", "3", "mk_name_ex_table", "4", "mk_nick_b_table", "5", "mk_name_fa_table", "dice", "num", "table", "11", "12", "13", "14", "15", "16", "22", "23", "24", "25", "26", "33", "34", "35", "36", "44", "45", "4