,EAEN,CAACK,EAAD,EAAKL,SAAL,CAFM,EAGN,CAACM,EAAD,EAAKN,QAAL,CAHM,EAIN,CAACO,EAAD,EAAKP,QAAL,CAJM,EAKN,CAACQ,EAAD,EAAKR,UAAL,CALM,EAMN,CAACS,EAAD,EAAKT,eAAL,CANM,EAON,CAACU,EAAD,EAAKV,eAAL,CAPM,EAQN,CAACW,EAAD,EAAKX,aAAL,CARM,EASN,CAACY,EAAD,EAAKZ,aAAL,CATM,EAUN,CAACa,EAAD,EAAKb,cAAL,CAVM,EAWN,CAACc,EAAD,EAAKd,UAAL,CAXM,EAYN,CAACe,EAAD,EAAKf,gBAAL,CAZM,EAaN,CAACgB,EAAD,EAAKhB,eAAL,CAbM,EAcN,CAACiB,EAAD,EAAKjB,eAAL,CAdM,EAeN,CAACkB,EAAD,EAAKlB,SAAL,CAfM,EAgBN,CAACmB,EAAD,EAAKnB,YAAL,CAhBM,EAiBN,CAACoB,EAAD,EAAKpB,cAAL,CAjBM,EAkBN,CAACqB,EAAD,EAAKrB,YAAL,CAlBM,EAmBN,CAACsB,EAAD,EAAKtB,WAAL,CAnBM,EAoBN,CAACuB,EAAD,EAAKvB,UAAL,CApBM,EAqBN,CAACyB,EAAD,EAAKzB,aAAL,CArBM;UAwBR,OAAOvB,IAAAkD,qBAAAA,CAAoBzB,GAApB,EAAyBC,KAAzBwB;QAzBT3B,CAAAA;MA3LFzB,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>474, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom/placename_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdom\n      # 地名決定表\n      def mk_pn_decide_table(num)\n        output = \"\"\n\n        d1 = @randomizer.roll_once(6)\n        d2 = @randomizer.roll_once(6)\n        debug(\"d1\", d1)\n        debug(\"d2\", d2)\n\n        d1 = (d1 / 2.0).ceil.to_i\n        d2 = (d2 / 2.0).ceil.to_i\n\n        num.times do |_i|\n          output += \"「\" + mk_decoration_table(d1) + mk_placename_table(d2) + \"」\"\n        end\n\n        return output\n      end\n\n      # 修飾決定表(1D6)\n      def mk_decoration_table(num)\n        debug(\"mk_decoration_table num\", num)\n\n        table = [\n          [1, lambda { mk_basic_decoration_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [2, lambda { mk_spooky_decoration_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [3, lambda { mk_katakana_decoration_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 地名決定表(1D6)\n      def mk_placename_table(num)\n        table = [\n          [1, lambda { mk_passage_placename_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [2, lambda { mk_natural_placename_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n          [3, lambda { mk_artifact_placename_table(@randomizer.roll_d66(D66SortType::ASC)) }],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 基本表(D66)\n      def mk_basic_decoration_table(num)\n        table = [\n          [11, \"欲望（よくぼう）\"],\n          [12, \"漂流（ひょうりゅう）\"],\n          [13, \"黄金（おうごん）\"],\n          [14, \"火達磨（ひだるま）\"],\n          [15, \"災厄（さいやく）\"],\n          [16, \"三日月（みかづき）\"],\n          [22, \"絡繰り（からくり）\"],\n          [23, \"流星（りゅうせい）\"],\n          [24, \"棘々（とげとげ）\"],\n          [25, \"鏡（かがみ）\"],\n          [26, \"銀鱗（ぎんりん）\"],\n          [33, \"螺旋（らせん）\"],\n          [34, \"七色（なないろ）\"],\n          [35, \"殉教（じゅんきょう）\"],\n          [36, \"水晶（すいしょう）\"],\n          [44, \"氷結（ひょうけつ）\"],\n          [45, \"忘却（ぼうきゃく）\"],\n          [46, \"幸福（こうふく）\"],\n          [55, \"妖精（ようせい）\"],\n          [56, \"霧雨（きりさめ）\"],\n          [66, \"夕暮れ（ゆうぐれ）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 不気味表(D66)\n      def mk_spooky_decoration_table(num)\n        table = [\n          [11, \"赤錆（あかさび）\"],\n          [12, \"串刺し（くしざし）\"],\n          [13, \"鬼蜘蛛（おにぐも）\"],\n          [14, \"蠍（さそり）\"],\n          [15, \"幽霊（ゆうれい）\"],\n          [16, \"髑髏（どくろ）\"],\n          [22, \"血溜まり（ちだまり）\"],\n          [23, \"臓物（ぞうもつ）\"],\n          [24, \"骸（むくろ）\"],\n          [25, \"鉤爪（かぎづめ）\"],\n          [26, \"犬狼（けんろう）\"],\n          [33, \"奈落（ならく）\"],\n          [34, \"大蛇（おろち）\"],\n          [35, \"地獄（じごく）\"],\n          [36, \"蚯蚓（みみず）\"],\n          [44, \"退廃（たいはい）\"],\n          [45, \"土竜（もぐら）\"],\n          [46, \"絶望（ぜつぼう）\"],\n          [55, \"夜泣き（よなき）\"],\n          [56, \"緑林（りょくりん）\"],\n          [66, \"どん底（どんぞこ）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # カタカナ表(D66)\n      def mk_katakana_decoration_table(num)\n        table = [\n          [11, \"マヨネーズ\"],\n          [12, \"ダイナマイト\"],\n          [13, \"ドラゴン\"],\n          [14, \"ボヨヨン\"],\n          [15, \"モケモケ\"],\n          [16, \"マヌエル\"],\n          [22, \"ダイス\"],\n          [23, \"ロマン\"],\n          [24, \"ウクレレ\"],\n          [25, \"エップカプ\"],\n          [26, \"カンパネルラ\"],\n          [33, \"マンチキン\"],\n          [34, \"バロック\"],\n          [35, \"ミサイル\"],\n          [36, \"ドッキリ\"],\n          [44, \"ブラック\"],\n          [45, \"好きなモンスターの名前\"],\n          [46, \"好きなトラップの名前\"],\n          [55, \"好きな単語表で\"],\n          [56, \"好きな名前決定表で\"],\n          [66, \"好きな数字の組み合わせ\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 通路系地名表(D66)\n      def mk_passage_placename_table(num)\n        table = [\n          [11, \"門（ゲート）\"],\n          [12, \"回廊（コリドー）\"],\n          [13, \"通り（ストリート）\"],\n          [14, \"小路（アレイ）\"],\n          [15, \"大路（アベニュー）\"],\n          [16, \"街道（ロード）\"],\n          [22, \"鉄道（ライン）\"],\n          [23, \"迷宮（メイズ）\"],\n          [24, \"坑道（トンネル）\"],\n          [25, \"坂（スロープ）\"],\n          [26, \"峠（パス）\"],\n          [33, \"運河（カナル）\"],\n          [34, \"水路（チャネル）\"],\n          [35, \"河（ストリーム）\"],\n          [36, \"堀（モート）\"],\n          [44, \"溝（ダイク）\"],\n          [45, \"階段（ステア）\"],\n          [46, \"辻（トレイル）\"],\n          [55, \"橋（ブリッジ）\"],\n          [56, \"穴（ホール）\"],\n          [66, \"柱廊（ストア）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 自然系地名表(D66)\n      def mk_natural_placename_table(num)\n        table = [\n          [11, \"砂漠（デザート）\"],\n          [12, \"丘陵（ヒル）\"],\n          [13, \"海（オーシャン）\"],\n          [14, \"森（フォレスト）\"],\n          [15, \"沼（ポンド）\"],\n          [16, \"海岸（コースト）\"],\n          [22, \"密林（ジャングル）\"],\n          [23, \"湖（レイク）\"],\n          [24, \"山脈（マウンテンズ）\"],\n          [25, \"平原（プレイン）\"],\n          [26, \"ヶ原（ランド）\"],\n          [33, \"荒野（ヒース）\"],\n          [34, \"渓谷（ヴァレー）\"],\n          [35, \"島（アイランド）\"],\n          [36, \"連峰（ピークス）\"],\n          [44, \"火山（ヴォルケイノ）\"],\n          [45, \"湿原（ウェットランド）\"],\n          [46, \"星雲（ネビュラ）\"],\n          [55, \"星（スター）\"],\n          [56, \"ヶ淵（プール）\"],\n          [66, \"雪原（スノウズ）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 人工系地名表(D66)\n      def mk_artifact_placename_table(num)\n        table = [\n          [11, \"城（キャッスル）\"],\n          [12, \"壁（ウォール）\"],\n          [13, \"砦（フォート）\"],\n          [14, \"地帯（ゾーン）\"],\n          [15, \"室（ルーム）\"],\n          [16, \"の間（チャンバー）\"],\n          [22, \"浴室（バス）\"],\n          [23, \"畑（ファーム）\"],\n          [24, \"館（ハウス）\"],\n          [25, \"座（コンスティレィション）\"],\n          [26, \"遺跡（ルイン）\"],\n          [33, \"ヶ浜（ビーチ）\"],\n          [34, \"塔（タワー）\"],\n          [35, \"墓場（グレイブ）\"],\n          [36, \"洞（ケイヴ）\"],\n          [44, \"堂（バジリカ）\"],\n          [45, \"野（フィールド）\"],\n          [46, \"書院（スタディ）\"],\n          [55, \"駅前（ステイション）\"],\n          [56, \"房（クラスター）\"],\n          [66, \"腐海（ケイオスシー）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdom>", "mk_pn_decide_table", "num", "output", "d1", "@randomizer", "roll_once", "6", "d2", "self", "debug", "/", "ceil", "to_i", "times", "block in mk_pn_decide_table", "_i", "block (2 levels) in mk_pn_decide_table", "+", "mk_decoration_table", "mk_placename_table", "table", "1", "lambda", "block in mk_decoration_table", "block (2 levels) in mk_decoration_table", "mk_basic_decoration_table", "roll_d66", "D66SortType::ASC", "D66SortType", "2", "mk_spooky_decoration_table", "3", "mk_katakana_decoration_table", "get_table_by_number", "block in mk_placename_table", "block (2 levels) in mk_placename_table", "mk_passage_placename_table", "mk_natural_placename_table", "mk_artifact_placename_ta