IAAAyK,SAAAA,CAAQ7K,sDAAR6K;EACAzK,IAAAyK,SAAAA,CAAQ7K,mDAAR6K;EACAzK,IAAAyK,SAAAA,CAAQ7K,+CAAR6K;EACAzK,IAAAyK,SAAAA,CAAQ7K,mDAAR6K;EACAzK,IAAAyK,SAAAA,CAAQ7K,8CAAR6K;EACA7K,OAAAI,IAAAyK,SAAAA,CAAQ7K,0CAAR6K;AAjdA7K;"}}, {:offset=>{:line=>1418, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/dice_table/table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module DiceTable\n    # 表を表すクラス\n    class Table\n      # @param key [String]\n      # @param locale [Symbol]\n      # @return [Table]\n      def self.from_i18n(key, locale)\n        table = I18n.t(key, locale: locale)\n        new(table[:name], table[:type], table[:items])\n      end\n\n      # @param [String] name 表の名前\n      # @param [String] type 項目を選ぶときのダイスロールの方法 '1D6'など\n      # @param [Array<String>] items 表の項目の配列\n      def initialize(name, type, items)\n        @name = name\n        @items = items.freeze\n\n        m = /(\\d+)D(\\d+)/i.match(type)\n        unless m\n          raise ArgumentError, \"Unexpected table type: \#{type}\"\n        end\n\n        @times = m[1].to_i\n        @sides = m[2].to_i\n      end\n\n      # 表を振る\n      # @param [BCDice] bcdice ランダマイザ\n      # @return [String] 結果\n      def roll(bcdice)\n        value = bcdice.roll_sum(@times, @sides)\n        return choice(value)\n      end\n\n      def choice(value)\n        index = value - @times\n        return RollResult.new(@name, value, @items[index])\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:DiceTable>", "<class:Table>", "from_i18n", "self", "key", "locale", "table", "I18n", "t", "new", "[]", "initialize", "name", "type", "items", "@name", "@items", "freeze", "m", "match", "raise", "ArgumentError", "@times", "1", "to_i", "@sides", "2", "roll", "bcdice", "value", "roll_sum", "choice", "index", "-", "RollResult"], :mappings=>"AAAAA,0CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAEEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAIEC,MAAIC,IAAJD,gBAAAA,qBAAmBE,GAAD,EAAMC,MAAxBH;AAAAA,UAAAA;;;UACEI,QAAQC,UAAIC,GAAAA,CAAGJ,GAAP,EAAY,oBAAA,UAAQC,MAAR,EAARG;UACZN,OAAAC,IAAAM,KAAAA,CAAIH,KAAKI,OAAAA,CAAC,MAADA,CAAT,EAAkBJ,KAAKI,OAAAA,CAAC,MAADA,CAAvB,EAAgCJ,KAAKI,OAAAA,CAAC,OAADA,CAArCD;QAFFP,CAAAA;;AAQAS,QAAAA,0BAAAA,sBAAeC,IAAD,EAAOC,IAAP,EAAaC,KAA3BH;AAAAA,UAAAA;;;UACEI,YAAQH;UACRI,aAASF,KAAKG,QAAAA,CAAAA;UAEdC,IAAI,cAAcC,OAAAA,CAAON,IAAPM;UAClB,KAAA,QAAOD,CAAP,CAAA;YACEf,IAAAiB,OAAAA,CAAMC,mBAAN,EAAsBV,yBAAD,GAAA,CAA0BE,IAA1B,CAArBO;UADF;UAIAE,aAASJ,CAACR,OAAAA,CAACa,CAADb,CAAGc,MAAAA,CAAAA;UACbb,OAAAc,CAAAA,aAASP,CAACR,OAAAA,CAACgB,CAADhB,CAAGc,MAAAA,CAAAA,CAAbC;QAVFd,CAAAA;;AAgBAgB,QAAAA,oBAAAA,gBAASC,MAATD;AAAAA,UAAAA;;;UACEE,QAAQD,MAAME,UAAAA,CAAUR,UAAhB,EAAwBG,UAAlBK;UACd,OAAO3B,IAAA4B,QAAAA,CAAOF,KAAPE;QAFTJ,CAAAA;QAKA1B,OAAA8B,sBAAAA,kBAAWF,KAAXE;AAAAA,UAAAA;;;UACEC,QAAcC,UAANJ,KAAMI,EAAEX,UAAFW;UACd,OAAOC,gBAAUzB,KAAAA,CAAKM,SAAf,EAAsBc,KAAtB,EAA6Bb,UAAMN,OAAAA,CAACsB,KAADtB,CAAzBD;QAFnBsB,CAAAA;MAjCF9B,GAAAA,WAAAA,EAAAA,IAAAA;IAFFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>1479, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom_basic/item_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdomBasic\n      WEAPON_ITEM_TABLE = DiceTable::D66Table.new(\n        \"武具アイテム表\",\n        D66SortType::ASC,\n        {\n          11 => \"だんびら\",\n          12 => \"網（だんびら）\",\n          13 => \"短剣\",\n          14 => \"戦斧\",\n          15 => \"盾\",\n          16 => \"ホウキ\",\n          22 => \"棘（だんびら）\",\n          23 => \"鑓\",\n          24 => \"石弓\",\n          25 => \"甲冑\",\n          26 => \"戦鎚\",\n          33 => \"鎖（だんびら）\",\n          34 => \"爆弾\",\n          35 => \"鉄砲\",\n          36 => \"大剣\",\n          44 => \"大弓（だんびら）\",\n          45 => \"徹甲弾\",\n          46 => \"拳銃\",\n          55 => \"手裏剣（だんびら）\",\n          56 => \"大砲\",\n          66 => \"籠手（だんびら）\",\n        }\n      )\n\n      LIFE_ITEM_TABLE = DiceTable::D66Table.new(\n        \"生活アイテム表\",\n        D66SortType::ASC,\n        {\n          11 => \"鍋\",\n          12 => \"家畜（鍋）\",\n          13 => \"バックパック\",\n          14 => \"クラッカー\",\n          15 => \"がまぐち\",\n          16 => \"マント\",\n          22 => \"裁縫道具（鍋）\",\n          23 => \"カード\",\n          24 => \"エプロン\",\n          25 => \"住民台帳\",\n          26 => \"携帯電話\",\n          33 => \"外套（鍋）\",\n          34 => \"肖像画\",\n          35 => \"衣装\",\n          36 => \"山吹色のお菓子\",\n          44 => \"鏡（鍋）\",\n          45 => \"眼鏡\",\n          46 => \"クレジットカード\",\n          55 => \"召喚鍵（鍋）\",\n          56 => \"魔道書\",\n          66 => \"宝石（鍋）\",\n        }\n      )\n\n      REST_ITEM_TABLE = DiceTable::D66Table.new(\n        \"回復アイテム表\",\n        D66SortType::ASC,\n        {\n          11 => \"チョコレート（お弁当）\",\n          12 => \"砂糖菓子（お弁当）\",\n          13 => \"特効薬\",\n          14 => \"保存食\",\n          15 => \"担架\",\n          16 => \"お弁当（チョコレート）\",\n          22 => \"バナナ（お弁当）\",\n          23 => \"お酒\",\n          24 => \"珈琲\",\n          25 => \"フルコース\",\n          26 => \"ポーション\",\n          33 => \"魔素水（お弁当）\",\n          34 => \"救急箱\",\n          35 => \"強壮剤\",\n          36 => \"迷宮保険\",\n          44 => \"魔薬（お弁当）\",\n          45 => \"科学調味料\",\n          46 => \"惚れ薬\",\n          55 => \"軟膏（お弁当）\",\n          56 => \"復活薬\",\n          66 => \"万能薬（お弁当）\",\n        }\n      )\n\n      SEARCH_ITEM_TABLE = DiceTable::D66Table.new(\n        \"探索アイテム表\",\n        D66SortType::ASC,\n        {\n          11 => \"拷問具（星の欠片）\",\n          12 => \"ロープ（星の欠片）\",\n          13 => \"旗\",\n          14 => \"お守り\",\n          15 => \"星の欠片（拷問具）\",\n          16 => \"パワーリスト\",\n          22 => \"松明（星の欠片）\",\n          23 => \"テント\",\n          24 => \"楽器\",\n          25 => \"工具\",\n          26 => \"使い魔\",\n          33 => \"迷宮迷彩（星の欠片）\",\n          34 => \"乗騎\",\n          35 => \"罠百科\",\n          36 => \"迷宮防護服\",\n          44 => \"聴診器（星の欠片）\",\n          45 => \"地図\",\n          46 => \"時計\",\n          55 => \"飛行騎（星の欠片）\",\n          56 => \"カボチャの馬車\",\n          66 => \"もぐら棒（星の欠片）\",\n        }\n      )\n\n      COMMON_ITEM_RANDOM_TABLE = DiceTable::ChainTable.new(\n        \"コモンアイテムランダム決定表\",\n        \"1D4\",\n        [\n          WEAPON_ITEM_TABLE,\n          LIFE_ITEM_TABLE,\n          REST_ITEM_TABLE,\n          SEARCH_ITEM_TABLE,\n        ]\n      )\n\n      NORMAL_RARE_ITEM_TABLE = DiceTable::D66GridTable.new(\n        \"基本レア一般アイテム表\",\n        [\n          [\"愚者の冠\", \"香水\", \"煙玉\", \"悪名\", \"藁人形\", \"王妃の鏡\"],\n          [\"星籠\", \"転ばぬ先の杖\", \"悟りの書\", \"鉛の兵隊\", \"黄金の林檎\", \"百年茸\"],\n          [\"愚者の冠\", \"香水\", \"煙玉\", \"悪名\", \"藁人形\", \"王妃の鏡\"],\n          [\"星籠\", \"転ばぬ先の杖\", \"悟りの書\", \"鉛の兵隊\", \"黄金の林檎\", \"百年茸\"],\n          [\"操りロープ\", \"盗賊の七つ道具\", \"露眼鏡\", \"災厄王の遺物\", \"魔法の鞍\", \"琵琶\"],\n          [\"兎の足\", \"視肉\", \"衛星帯\", \"魔法の絨毯\", \"軍配\", \"聖杯\"],\n        ]\n      )\n\n      ADVANCED_RARE_ITEM_TABLE = DiceTable::D66GridTable.new(\n        \"上級レア一般アイテム表\",\n        [\n          [\"砂時計週報\", \"兵糧丸\", \"遊星葉書\", \"百科辞典\", \"夢枕\", \"蓄音機\"],\n          [\"砂時計週報\", \"兵糧丸\", \"遊星葉書\", \"百科辞典\", \"夢枕\", \"蓄音機\"],\n          [\"水晶球\", \"狭間の棺桶\", \"不思議なたまご\", \"魔法瓶\", \"不死鳥の羽飾り\", \"紅葫蘆\"],\n          [\"水晶球\", \"狭間の棺桶\", \"不思議なたまご\", \"魔法瓶\", \"不死鳥の羽飾り\", \"紅葫蘆\"],\n          [\"打ち出の小槌\", \"消火器\", \"滅びの予言書\", \"召魔鏡\", \"鉄仮面\", \"愛\"],\n          [\"打ち出の小槌\", \"消火器\", \"滅びの予言書\", \"召魔鏡\", \"鉄仮面\", \"愛\"],\n        ]\n      )\n\n      RARE_ITEM_RANDOM_TABLE = DiceTable::ChainTable.new(\n        \"レア一般アイテムランダム決定表\",\n        \"1D6\",\n        [\n          NORMAL_RARE_ITEM_TABLE,\n          NORMAL_RARE_ITEM_TABLE,\n          NORMAL_RARE_ITEM_TABLE,\n          ADVANCED_RARE_ITEM_TABLE,\n          ADVANCED_RARE_ITEM_TABLE,\n          ADVANCED_RARE_ITEM_TABLE,\n        ]\n      )\n\n      NORMAL_RARE_WEAPON_ITEM_TABLE = DiceTable::D66GridTable.new(\n        \"基本レア武具アイテム表\",\n        [\n          [\"蛍矢\", \"小麦粉\", \"喇叭銃\", \"まわし\", \"しゃべる剣\", \"大盾\"],\n          [\"王笏\", \"ぬいぐるみ\", \"魔杖\", \"獣の毛皮\", \"バカには見えない鎧\", \"ビキニアーマー\"],\n          [\"蛍矢\", \"小麦粉\", \"喇叭銃\", \"まわし\", \"しゃべる剣\", \"大盾\"],\n          [\"王笏\", \"ぬいぐるみ\", \"魔杖\", \"獣の毛皮\", \"バカには見えない鎧\", \"ビキニアーマー\"],\n          [\"チェインソード\", \"輝く者\", \"貪る者\", \"滅ぼす者\", \"機械の体\", \"刈り取る者\"],\n          [\"断ち切る者\", \"竜の鱗鎧\", \"射貫く者\", \"貫く者\", \"剥ぎ取る者\", \"王剣\"],\n        ]\n      )\n\n      ADVANCED_RARE_WEAPON_ITEM_TABLE = DiceTable::D66GridTable.new(\n        \"上級レア武具アイテム表\",\n        [\n          [\"虚弾\", \"小鬼の襟巻\", \"眼弾\", \"釣竿\", \"虹柱\", \"服従の鞭\"],\n          [\"虚弾\", \"小鬼の襟巻\", \"眼弾\", \"釣竿\", \"虹柱\", \"服従の鞭\"],\n          [\"星の杖\", \"聖印\", \"迷い傘\", \"邪眼\", \"徒手空拳\", \"隠れ兜\"],\n          [\"星の杖\", \"聖印\", \"迷い傘\", \"邪眼\", \"徒手空拳\", \"隠れ兜\"],\n          [\"太刀鋏\", \"破城槌\", \"黄金の鶴嘴\", \"ムラサマ\", \"君主の衣\", \"蒸気甲冑\"],\n          [\"太刀鋏\", \"破城槌\", \"黄金の鶴嘴\", \"ムラサマ\", \"君主の衣\", \"蒸気甲冑\"],\n        ]\n      )\n\n      RARE_WEAPON_ITEM_RANDOM_TABLE = DiceTable::ChainTable.new(\n        \"レア武具アイテムランダム決定表\",\n        \"1D6\",\n        [\n          NORMAL_RARE_WEAPON_ITEM_TABLE,\n          NORMAL_RARE_WEAPON_ITEM_TABLE,\n          NORMAL_RARE_WEAPON_ITEM_TABLE,\n          ADVANCED_RARE_WEAPON_ITEM_TABLE,\n          ADVANCED_RARE_WEAPON_ITEM_TABLE,\n          ADVANCED_RARE_WEAPON_ITEM_TABLE,\n        ]\n      )\n\n      # デヴァイス・ファクトリー\n      def roll_device_factory_table(num)\n        item = ITEM_RANDOM_TABLE.roll(@randomizer).last_body\n        intro = \"デヴァイス・ファクトリー表 (特性\#{num}個) ＞ ベースアイテム：\#{item}（もしくは任意のアイテム）\"\n\n        num = [0, num].max\n        feature_list = Array.new(num) { ITEM_FEATURES_TABLE.roll(randomizer) }\n        return [intro, *feature_list].join(\"\\n\")\n      end\n\n      # アイテムカテゴリ決定表 (1D6)\n      ITEM_RANDOM_TABLE = DiceTable::ChainTable.new(\n        \"アイテムカテゴリ決定表\",\n        \"1D6\",\n        [\n          WEAPON_ITEM_TABLE,\n          LIFE_ITEM_TABLE,\n          REST_ITEM_TABLE,\n          SEARCH_ITEM_TABLE,\n          RARE_ITEM_RANDOM_TABLE,\n          RARE_WEAPON_ITEM_RANDOM_TABLE,\n        ]\n      )\n\n      class ItemFeature\n        def initialize(name, type, items)\n          @name = name\n          @times, @sides = type.split(\"D\", 2).map(&:to_i)\n          @items = items\n        end\n\n        def choice(randomizer)\n          dice = randomizer.roll_sum(@times, @sides)\n          index = dice - @times\n\n          chosen = @items[index]\n          chosen = chosen.choice(randomizer) if chosen.respond_to?(:choice)\n\n          return \"[\#{dice}]\#{chosen}\"\n        end\n      end\n\n      ITEM_POWER_TABLE = ItemFeature.new(\n        \"神力決定表\",\n        \"1D6\",\n        [\n          \"才覚\",\n          \"魅力\",\n          \"探索\",\n          \"武勇\",\n          \"《器》\",\n          \"《回避値》\",\n        ]\n      )\n\n      ITEM_JYUMON_TABLE = ItemFeature.new(\n        \"呪紋決定表\",\n        \"2D6\",\n        [\n          \"ランダムに選んだモンスターカテゴリ1種のうち、【人類の敵】未習得かつ（2D6）レベル以下のモンスタースキル\",\n          \"便利スキルから好きなスキル1種\",\n          \"芸能スキルから好きなスキル1種\",\n          \"迷宮スキルから好きなスキル1種\",\n          \"星術スキルから好きなスキル1種\",\n          \"一般スキルから好きなスキル1種\",\n          \"召喚スキルから好きなスキル1種\",\n          \"科学スキルから好きなスキル1種\",\n          \"交渉スキルから好きなスキル1種\",\n          \"神官のクラススキルから好きなスキル1種\",\n          \"生まれ表を使用してランダムに決めたジョブのジョブスキル\",\n        ]\n      )\n\n      ITEM_JYUKA_TABLE = ItemFeature.new(\n        \"呪禍表\",\n        \"1D6\",\n        [\n          \"このアイテムを装備している限り「呪い3」の変調を受ける\",\n          \"このアイテムを装備している限り「肥満3」の変調を受ける\",\n          \"このアイテムを装備している限り「憤怒」の変調を受ける\",\n          \"このアイテムを装備している限り「毒2」の変調を受ける\",\n          \"このアイテムを装備している限り、条件を満たしても誰とも人間関係を結べない\",\n          \"このアイテムを装備している限り「散漫1」の変調を受ける\",\n        ]\n      )\n\n      GENDER_TABLE = ItemFeature.new(\n        \"性別決定表\",\n        \"1D6\",\n        [\n          \"性別が男であること\",\n          \"性別が女であること\",\n          \"性別が男であること\",\n          \"性別が女であること\",\n          \"性別が男であること\",\n          \"性別が女であること\",\n        ]\n      )\n\n      ITEM_APTITUDE_TABLE = ItemFeature.new(\n        \"適正表\",\n        \"1D6\",\n        [\n          \"ランダムなクラス1種であること\",\n          \"生まれ表でランダムに選んだジョブであること\",\n          GENDER_TABLE,\n          \"上級ジョブであること\",\n          \"モンスタースキルを修得していること\",\n          \"童貞、もしくは処女であること\",\n        ]\n      )\n\n      ITEM_ATTRIBUTE_TABLE = ItemFeature.new(\n        \"属性表\",\n        \"1D6\",\n        [\n          \"自然の力。10レベル以下の人間カテゴリのモンスターと重要NPC\",\n          \"幻夢の力。10レベル以下の異形と呪物カテゴリのモンスター\",\n          \"星炎の力。10レベル以下の魔獣と鬼族カテゴリのモンスター\",\n          \"暗黒の力。10レベル以下の妖精と天使カテゴリのモンスター\",\n          \"聖なる力。10レベル以下の死霊と深人カテゴリのモンスター\",\n          \"災厄の力。支配者として設定されているキャラクター\",\n        ]\n      )\n\n      class ItemFeaturesTable\n        def initialize\n          @items = [\n            [\"そのアイテムは「\", ITEM_POWER_TABLE, \"」の神力を宿す。\"],\n            [\"そのアイテムは寿命を持つ。寿命の値を決定する。\\nさらに、\", self],\n            [\"そのアイテムは境界障壁を持つ。《HP》の値を決定する。\"],\n            [\"そのアイテムは銘を持つ。銘を決定する。\"],\n            [\"そのアイテムは合成具である。もう1つの機能は「\", ITEM_RANDOM_TABLE, \"」である。\"],\n            [\"そのアイテムにレベルがあれば、レベルを1点上昇する。\\nレベルが設定されていなければ、\", self],\n            [\"そのアイテムは「\", ITEM_JYUMON_TABLE, \"」の呪紋を持つ。\"],\n            [\"そのアイテムは「\", ITEM_JYUKA_TABLE, \"」の呪禍を持つ。\\nさらに、\", self],\n            [\"そのアイテムは高価だ。価格を設定する。\"],\n            [\"そのアイテムは「条件：\", ITEM_APTITUDE_TABLE, \"」の適正を持つ。\\nさらに、\", self],\n            [\"そのアイテムは「\", ITEM_ATTRIBUTE_TABLE, \"」の属性を持つ。\"],\n          ].freeze\n        end\n\n        def roll(randomizer)\n          dice = randomizer.roll_sum(2, 6)\n          index = dice - 2\n          chosen_row = @items[index]\n\n          string_list = chosen_row.map do |s|\n            case s\n            when String\n              s\n            when ItemFeature\n              s.choice(randomizer)\n            else\n              s.roll(randomizer)\n            end\n          end\n\n          return \"特性[\#{dice}]：\#{string_list.join('')}\"\n        end\n      end\n\n      ITEM_FEATURES_TABLE = ItemFeaturesTable.new().freeze\n\n      ITEM_TABLES = {\n        \"WIT\" => WEAPON_ITEM_TABLE,\n        \"LIT\" => LIFE_ITEM_TABLE,\n        \"RIT\" => REST_ITEM_TABLE,\n        \"SIT\" => SEARCH_ITEM_TABLE,\n        \"CIR\" => COMMON_ITEM_RANDOM_TABLE,\n        \"NRUT\" => NORMAL_RARE_ITEM_TABLE,\n        \"ARUT\" => ADVANCED_RARE_ITEM_TABLE,\n        \"RUIR\" => RARE_ITEM_RANDOM_TABLE,\n        \"NRWT\" => NORMAL_RARE_WEAPON_ITEM_TABLE,\n        \"ARWT\" => ADVANCED_RARE_WEAPON_ITEM_TABLE,\n        \"RWIR\" => RARE_WEAPON_ITEM_RANDOM_TABLE,\n      }.freeze\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdomBasic>", "DiceTable::D66Table", "DiceTable", "new", "D66SortType::ASC", "D66SortType", "11", "12", "13", "14", "15", "16", "22", "23", "24", "25", "26", "33", "34", "35", "36", "44", "45", "46", "55", "56", "66", "DiceTable::ChainTable", "WEAPON_ITEM_TABLE", "LIFE_ITEM_TABLE", "REST_ITEM_TABLE", "SEARCH_ITEM_TABLE", "DiceTable::D66GridTable", "NORMAL_RARE_ITEM_TABLE", "ADVANCED_RARE_ITEM_TABLE", "NORMAL_RARE_WEAPON_ITEM_TABLE", "ADVANCED_RARE_WEAPON_ITEM_TABLE", "roll_device_factory_table", "num", "item", "ITEM_RANDOM_TABLE", "roll", "@randomizer", "last_body", "intro", "0", "max", "feature_list", "Array", "block in roll_device_factory_table", "block (2 levels) in roll_device_factory_table", "ITEM_FEATURES_TABLE", "self", "randomizer", "join", "RARE_ITEM_RANDOM_TABLE", "RARE_WEAPON_ITEM_RANDOM_TABLE", "<class:ItemFeature>", "initialize", "name", "type", "items", "@name", "map", "split", "2", "to_proc", "@times", "@sides", "@items", "choice", "dice", "roll_sum", "index", "-", "chosen", "[]", "respond_to?", "ItemFeature", "GENDER_TABLE", "<class:ItemFeaturesTable>", "ITEM_POWER_TABLE", "ITEM_JYUMON_TABLE", "ITEM_JYUKA_TABLE", "ITEM_APTITUDE_TABLE", "ITEM_ATTRIBUTE_TABLE", "freeze", "6", "chosen_row", "string_list", "block in roll", "s", "block (2 levels) in roll", "Str