AAhC,CAPO,EAQP,CAACA,UAAD,EAAayB,sBAAb,EAA+BzB,gBAA/B,EAAiDN,IAAjD,CARO,EASP,CAACM,qBAAD,CATO,EAUP,CAACA,aAAD,EAAgB0B,yBAAhB,EAAqC1B,gBAArC,EAAuDN,IAAvD,CAVO,EAWP,CAACM,UAAD,EAAa2B,0BAAb,EAAmC3B,UAAnC,CAXO,CAYR4B,QAAAA,CAAAA,CAZDjB;UADFX,CAAAA;UAgBAsB,OAAAvC,oBAAAA,gBAASY,UAATZ;AAAAA,YAAAA;;;YACE8B,OAAOlB,UAAUmB,UAAAA,CAAUP,CAApB,EAAuBsB,CAAbf;YACjBC,QAAaC,UAALH,IAAKG,EAAET,CAAFS;YACbc,aAAanB,UAAMO,OAAAA,CAACH,KAADG;YAEnBa,cAAwB1B,MAAVyB,UAAUzB,OAAAA,EAAAA,EAAAA,EAAV2B,aAAmBC,CAAnBD,EAAAE;;;cAAmB;cAE/B,IAAA,QAAKC,YAAL,EADAC,CAAAA,YAAKH,CAALG,CACA,CAAA;gBACEF,OAAAD;cADF,OAEA,IAAA,QAAKb,iBAAL,EAjWZ,SAiWY,CAAA;gBACEc,OAAAD,CAACrB,QAAAA,CAAQjB,UAARiB;cADH;gBAGEsB,OAAAD,CAAClD,MAAAA,CAAMY,UAANZ;cAHH,EAJYiD,CAAU3B;YAWxB,OAAQtB,KAAD,GAAA,CAAM8B,IAAN,CAAA,GAAW9B,IAAX,GAAA,CAAegD,WAAWnC,MAAAA,CAAMb,EAANa,CAA1B;UAhBTb,CAAAA;QAjBFuC,GAAAA,WAAAA,EAAAA,IAAAA;QAqCA,+CAAsBe,uBAAiB5F,KAAAA,CAAAA,CAAMmF,QAAAA,CAAAA,CAA7C;QAEAtF,OAAA,uCAAc,6FAAA,OACH4B,uBADG,EAAA,OAEHC,qBAFG,EAAA,OAGHC,qBAHG,EAAA,OAIHC,uBAJG,EAAA,OAKHiE,8BALG,EAAA,QAMF/D,4BANE,EAAA,QAOFC,8BAPE,EAAA,QAQFqB,4BARE,EAAA,QASFpB,mCATE,EAAA,QAUFC,qCAVE,EAAA,QAWFoB,mCAXE,EAYb8B,QAAAA,CAAAA,CAZD;MA1WFtF,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>1600, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom_basic/kingdom_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdomBasic\n      # 王国名決定表１(D66)\n      # override\n      def mk_kingdom_name_1_table(num)\n        table = [\n          [11, \"暗黒、クラヤミ、星灯り、カガヤキ、シャイニング、黄昏、暁\"],\n          [12, \"王政、帝政、爆発、回転\"],\n          [13, \"超、スーパー、秘密主義、高等、ハイ、どん底\"],\n          [14, \"共和制、立憲、公立、私立\"],\n          [15, \"古代、新、ネオ、笑う、歌う\"],\n          [16, \"共産、社会主義、自由、自由主義、ぶらり、ここは\"],\n          [22, \"専制、民主主義、踊る、眠れる\"],\n          [23, \"第三、最終、特別、標準\"],\n          [24, \"神聖、聖、セント、絶対主義、現代、未来\"],\n          [25, \"正統、本格、裏、偽、リバース、怪奇、幻想\"],\n          [26, \"本家、元祖、荒ぶる、分かる\"],\n          [33, \"大、グレート、小、スモール、必殺、淡麗\"],\n          [34, \"天階、上、上方、深階、下、下方、異世界、現代\"],\n          [35, \"東、東方、西、西方、かわいい、世界の\"],\n          [36, \"北、北方、南、南方、赤い、緑の\"],\n          [44, \"中央、辺境、飛び出せ、戦え\"],\n          [45, \"独立、統一、ちはやぶる、八雲立つ\"],\n          [46, \"永世、臨時、ザ、ラ\"],\n          [55, \"さよなら、おはよう、太平、汎\"],\n          [56, \"好戦的、平和的、素晴らしき、衝撃の\"],\n          [66, \"優しい、怖い、ぼくらの、みんなの\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 王国名決定表２(D66)\n      # override\n      def mk_kingdom_name_2_table(num)\n        table = [\n          [11, \"凸凹、仄仄、子ども、大人\"],\n          [12, \"迷宮、ダンジョン、監獄、封印、墓場\"],\n          [13, \"グランドゼロ、エレベータ、コンパス、行き止まり\"],\n          [14, \"サイコロ、ダイス、ランダム、ファンブル、ピンゾロ、シャッフル\"],\n          [15, \"災厄、征服、無敵、野蛮\"],\n          [16, \"デーモン、魔神、エンジェル、天使、超人、哲人\"],\n          [22, \"野球、サッカー、クリケット、バドミントン\"],\n          [23, \"商、武、科学、クラフト\"],\n          [24, \"ドラゴン、龍、ヴァンパイア、吸血鬼、ヒューマン、人間、フェアリー、妖精\"],\n          [25, \"猫、狼、キリン、キンギョ\"],\n          [26, \"バナナ、ボルシチ、スシ、チーズ\"],\n          [33, \"ファンタジー、魔法、マジカル、冒険、英雄\"],\n          [34, \"大砲、刀剣、装甲、鉄拳\"],\n          [35, \"ひきこもり、乙女、3D、転生\"],\n          [36, \"崖っぷち、片隅、路地裏、炎上\"],\n          [44, \"電脳、浪漫、蒸気、退廃\"],\n          [45, \"コンプライアンス、ダイバーシティ、アグリー、ウィンウィン\"],\n          [46, \"ローマ、中華、エジプト、アステカ\"],\n          [55, \"(単語表1で決定)、(単語表2で決定)、(単語表3で決定)、(単語表4で決定)\"],\n          [56, \"(プレイ会場の地名)、(GMの出身地)、(この表を使用した者の住所)、(GMの苗字)\"],\n          [66, \"(国王の名前。後で決定)、(国王のジョブ名。後で決定)、(ランダムな武具アイテム名)、(ランダムな日常アイテム名)\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 王国名決定表３(D66)\n      # override\n      def mk_kingdom_name_3_table(num)\n        table = [\n          [11, \"王国、キングダム、王朝\"],\n          [12, \"会社、公社、本舗\"],\n          [13, \"学園、学校、食堂\"],\n          [14, \"汗国、国\"],\n          [15, \"合衆国、政府\"],\n          [16, \"共同体、共和国\"],\n          [22, \"司教国、教皇領\"],\n          [23, \"星、伯国\"],\n          [24, \"公国、大公国\"],\n          [25, \"市、シティ、ポリス、都、のみやこ\"],\n          [26, \"自治国、騎士団領\"],\n          [33, \"植民地、統一機構\"],\n          [34, \"帝国、皇国\"],\n          [35, \"同盟、機関\"],\n          [36, \"首長国、土侯国\"],\n          [44, \"幕府、藩王国\"],\n          [45, \"領、クラブ\"],\n          [46, \"村、町、街\"],\n          [55, \"横丁、亭、社中\"],\n          [56, \"ランド、戦線\"],\n          [66, \"連邦、連合\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 王国環境表(1D6)\n      def mk_kingdom_environment_table(num)\n        d1 = @randomizer.roll_once(6)\n        functionTable = [\n          [1, lambda { mk_technic_decide_table(d1) }],\n          [2, lambda { mk_national_style_decide_table(d1) }],\n          [3, lambda { mk_resource_decide_table(d1) }],\n          [4, lambda { mk_facility_decide_table(d1) }],\n          [5, lambda { mk_human_resources_decide_table(d1) }],\n          [6, lambda { mk_blood_decide_table(d1) }],\n        ]\n        return get_table_by_number(num, functionTable)\n      end\n\n      # 技術決定表（1d6）\n      def mk_technic_decide_table(num)\n        table = [\n          [1, \"あなたの国は、魔法の研究、開発に力をそそぐ魔道国家である。その国のキャラクターは、星術、召喚、科学スキルの判定を行うとき、その達成値が1点上昇する（最大3点まで上昇する。4回目以降は振り直すこと）。\"],\n          [2, \"あなたの国は、神話的遺物の逸話が残っている。レア一般アイテムの中からランダムに1種を選ぶ。そのレアアイテムのレシピを持っている。【王宮】のある部屋に、そのレア一般アイテムの名前を記入すること。\"],\n          [3, \"あなたの国は、英雄が用いた武具の伝説が残っている。レア武具アイテムの中からランダムに1種を選ぶ。そのレアアイテムのレシピを持っている。【王宮】のある部屋に、そのレア武具アイテムの名前を記入すること。\"],\n          [4, \"あなたの国は、有名な職人たちが揃う工業国家である。コモンアイテムを作成するとき、それらのアイテムを作成するための必要国力が1点高いものとして扱う。\"],\n          [5, \"あなたの国は、質実剛健な兵士たちが揃っている。その国のキャラクターは、《配下》最大値が1人上昇する（最大2人まで上昇する。3回目以降は振り直すこと）。\"],\n          [6, \"あなたの国は、過去に列強に臣従し、いまでも友好的な関係を築いている。（1D6）を振ること。1ならダイナマイト帝国、2なら千年王朝、3ならメトロ汗国、4ならハグルマ資本主義神聖共和国との関係が「友好」になる。5や6なら振り直すこと。また、その列強の列強系施設1軒を獲得する。\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 国風決定表（1d6）\n      def mk_national_style_decide_table(num)\n        table = [\n          [1, \"あなたの国は、古くからあり、伝統を重んじる気風を持つ。宮廷系施設を建設・発展するための価格が1MG軽減される（最大2MGまで軽減される。3回目以降は振り直すこと）。\"],\n          [2, \"あなたの国は、広い国土と高い天井に恵まれている。居住系施設を建設するための価格が1MG軽減される（最大2MGまで軽減される。3回目以降は振り直すこと）。\"],\n          [3, \"あなたの国は、夏星が豊富で、作物がたくさん収穫できる。生産系施設を建設・発展するための価格が1MG軽減される。（最大2MGまで軽減される。3回目以降は振り直すこと）。\"],\n          [4, \"あなたの国は、しっかりとした規律と礼節があり、それを守る風潮がある。公共系施設を建設・発展するための価格が1MG軽減される（最大2MGまで軽減される。3回目以降は振り直すこと）。\"],\n          [5, \"あなたの国は、芸術を奨励し、文化的な国民性を誇る。娯楽系施設を建設・発展するための価格が1MG軽減される（最大2MGまで軽減される。3回目以降は振り直すこと）。\"],\n          [6, \"あなたの国は、物を大切にし、質素な生活を心がける気風を持つ。保管系施設を建設・発展するための価格が1MG軽減される（最大2MGまで軽減される。3回目以降は振り直すこと）。\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 資源決定表（1d6）\n      def mk_resource_decide_table(num)\n        table = [\n          [1, \"あなたの国は、過去に善政がしかれ、非常に安定している。セッション開始時の《民の声》の値が1点上昇する（最大3点まで上昇する。4回目以降は振り直すこと）。\"],\n          [2, \"あなたの国は、天然の要害に囲まれており、外敵に襲われにくい。《民》が（2D6）人増加する。\"],\n          [3, \"あなたの国には、名工がつくった武器がある。ランダムに選んだ武具アイテム1個を獲得する。その武具アイテムはレベル1として扱う。\"],\n          [4, \"あなたの国には、先頃友誼を誓い合った同盟国がある。王国シートの周辺階域から、ランダムに未知の土地1つを選ぶ。その土地に、王国を1つ設定すること。この国は【特産物】を持つ。「相場表」を使って、【特産物】の素材をランダムに決定すること。この国との関係は「同盟」となる。\"],\n          [5, \"あなたの国で先頃、前王の隠し財産が発見された。《予算》を（1D6） MG獲得する。\"],\n          [6, \"あなたの国には、隠し扉があった。「自国の地理」を決定したあと、追加で通路を2本引くことができる。通路でつながっている部屋は領土として扱う。\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 施設決定表（1d6）\n      def mk_facility_decide_table(num)\n        table = [\n          [1, \"あなたの国は、その地方を代々統治する伝統ある王国だ。宮廷系施設の中からランダムに1種を選ぶ。自国にその施設を1件建設する。\"],\n          [2, \"あなたの国は、交易路の周囲にあり、多くの人々が流入する。居住系施設の中からランダムに1種を選ぶ。自国にその施設を1件建設する。\"],\n          [3, \"あなたの国は、職人気質のものが多く、物作りがさかんだ。生産系施設の中からランダムに1種を選ぶ。自国にその施設を1件建設する。\"],\n          [4, \"あなたの国は民を第一に考え、福祉に力を入れている。公共系施設の中からランダムに1種を選ぶ。自国にその施設を1件建設する。\"],\n          [5, \"あなたの国は、歓楽国家として知られ、他国からの客もよく出入りしている。娯楽系施設の中からランダムに1種を選ぶ。自国にその施設を1件建設する。\"],\n          [6, \"あなたの国は、辺境に位置する王国だ。周辺には怪物も少ない。保管系施設の中からランダムに1種を選ぶ。自国にその施設を1件建設する。\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 人材決定表（1d6）\n      def mk_human_resources_decide_table(num)\n        table = [\n          [1, \"あなたの国には、高い見識を持つ知識人がいる。「才覚系生まれ表」でランダムにジョブ1種を選ぶ。そのジョブの逸材を1人獲得する。逸材の名前を決定すること。\"],\n          [2, \"あなたの国には、皆を魅了する好人物がいる。「魅了系生まれ表」でランダムにジョブ1種を選ぶ。そのジョブの逸材を1人獲得する。逸材の名前を決定すること。\"],\n          [3, \"あなたの国には、巧みな技術を持つ専門家がいる。「探索系生まれ表」でランダムにジョブ1種を選ぶ。そのジョブの逸材を1人獲得する。逸材の名前を決定すること。\"],\n          [4, \"あなたの国には、見事な腕前の戦士がいる。「武勇系生まれ表」でランダムにジョブ1種を選ぶ。そのジョブの逸材を1人獲得する。逸材の名前を決定すること。\"],\n          [5, \"あなたの国は、怪物と共存している？ （1D6）を振ること。1なら【小鬼】、2なら【ウマトカゲ】、3なら【ドワーフ】、4なら【エルフ】、5なら【キンギョ】、6なら【ごんぎつね】の《モンスターの民》を（1D6）人獲得する。\"],\n          [6, \"あなたの国は、ここしばらく怪物や敵国の襲撃もなく、平和な日々が続いていた。《民》が（2D6）人増加する。\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 血族決定表（1d6）\n      def mk_blood_decide_table(num)\n        table = [\n          [1, \"あなたの国は、鬼族の蹂躙を受けた歴史を持ち、混血が進んでいる。その国のキャラクターは新たにスキルを修得するとき、鬼族カテゴリの自分のレベル以下のモンスターが修得しているモンスタースキルの中から、修得するスキルを選ぶことができるようになる。\"],\n          [2, \"あなたの国は、古代に迷宮から姿を消した妖精女王の末裔といわれている。その国のキャラクターは新たにスキルを修得するとき、妖精カテゴリの自分のレベル以下のモンスターが修得しているモンスタースキルの中から、修得するスキルを選ぶことができるようになる。\"],\n          [3, \"あなたの国は、偉大なる古龍が迷宮と化した場所であり、その尊い血を引いているといわれる。その国のキャラクターは新たにスキルを修得するとき、魔獣カテゴリの自分のレベル以下のモンスターが修得しているモンスタースキルの中から、修得するスキルを選ぶことができるようになる。\"],\n          [4, \"あなたの国は、魔階からやってきた魔王の子供たちといわれている。その国のキャラクターは新たにスキルを修得するとき、異形カテゴリの自分のレベル以下のモンスターが修得しているモンスタースキルの中から、修得するスキルを選ぶことができるようになる。\"],\n          [5, \"あなたの国は、死霊術師によって死者の王国に変えられた悲劇的な過去を持つ。その国のキャラクターは新たにスキルを修得するとき、死霊カテゴリの自分のレベル以下のモンスターが修得しているモンスタースキルの中から、修得するスキルを選ぶことができるようになる。\"],\n          [6, \"あなたの国は、古代の錬金術師たちによって造られた人造生命が多数使役されている。その国のキャラクターは新たにスキルを修得するとき、呪物カテゴリの自分のレベル以下のモンスターが修得しているモンスタースキルの中から、修得するスキルを選ぶことができるようになる。\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdomBasic>", "mk_kingdom_name_1_table", "num", "table", "11", "12", "13", "14", "15", "16", "22", "23", "24", "25", "26", "33", "34", "35", "36", "44", "45", "46", "55", "56", "66", "self", "get_table_by_number", "mk_kingdom_name_2_table", "mk_kingdom_name_3_table", "mk_kingdom_environment_table", "d1", "@randomizer", "roll_once", "6", "functionTable", "1", "lambda", "block in mk_kingdom_environment_table", "block (2 levels) in mk_kingdom_environment_table", "mk_technic_decide_table", "2", "mk_national_style_decide_table", "3", "mk_resource_decide_table", "4", "mk_facility_decide_table", "5", "mk_human_resources_decide_table", "mk_blood_decide_table"], :mappings=>"AAAAA,wEAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;;AAGEC,QAAAA,uCAAAA,mCAA4BC,GAA5BD;AAAAA,UAAAA;;;UACEE,QAAQ,CACN,CAACC,EAAD,EAAKH,8BAAL,CADM,EAEN,CAACI,EAAD,EAAKJ,aAAL,CAFM,EAGN,CAACK,EAAD,EAAKL,uBAAL,CAHM,EAIN,CAACM,EAAD,EAAKN,cAAL,CAJM,EAKN,CAACO,EAAD,EAAKP,eAAL,CALM,EAMN,CAACQ,EAAD,EAAKR,yBAAL,CANM,EAON,CAACS,EAAD,EAAKT,gBAAL,CAPM,EAQN,CAACU,EAAD,EAAKV,aAAL,CARM,EASN,CAACW,EAAD,EAAKX,qBAAL,CATM,EAUN,CAACY,EAAD,EAAKZ,sBAAL,CAVM,EAWN,CAACa,EAAD,EAAKb,eAAL,CAXM,EAYN,CAACc,EAAD,EAAKd,qBAAL,CAZM,EAaN,CAACe,EAAD,EAAKf,wBAAL,CAbM,EAcN,CAACgB,EAAD,EAAKhB,oBAAL,CAdM,EAeN,CAACiB,EAAD,EAAKjB,iBAAL,CAfM,EAgBN,CAACkB,EAAD,EAAKlB,eAAL,CAhBM,EAiBN,CAACmB,EAAD,EAAKnB,kBAAL,CAjBM,EAkBN,CAACoB,EAAD,EAAKpB,WAAL,CAlBM,EAmBN,CAACqB,EAAD,EAAKrB,gBAAL,CAnBM,EAoBN,CAACsB,EAAD,EAAKtB,mBAAL,CApBM,EAqBN,CAACuB,EAAD,EAAKvB,kBAAL,CArBM;UAuBR,OAAOwB,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QAxBTzB,CAAAA;;AA6BA0B,QAAAA,uCAAAA,mCAA4BzB,GAA5ByB;AAAAA,UAAAA;;;UACExB,QAAQ,CACN,CAACC,EAAD,EAAKuB,cAAL,CADM,EAEN,CAACtB,EAAD,EAAKsB,mBAAL,CAFM,EAGN,CAACrB,EAAD,EAAKqB,yBAAL,CAHM,EAIN,CAACpB,EAAD,EAAKoB,gCAAL,CAJM,EAKN,CAACnB,EAAD,EAAKmB,aAAL,CALM,EAMN,CAAClB,EAAD,EAAKkB,wBAAL,CANM,EAON,CAACjB,EAAD,EAAKiB,sBAAL,CAPM,EAQN,CAAChB,EAAD,EAAKgB,aAAL,CARM,EASN,CAACf,EAAD,EAAKe,qCAAL,CATM,EAUN,CAACd,EAAD,EAAKc,cAAL,CAVM,EAWN,CAACb,EAAD,EAAKa,iBAAL,CAXM,EAYN,CAACZ,EAAD,EAAKY,sBAAL,CAZM,EAaN,CAACX,EAAD,EAAKW,aAAL,CAbM,EAcN,CAACV,EAAD,EAAKU,gBAAL,CAdM,EAeN,CAACT,EAAD,EAAKS,gBAAL,CAfM,EAgBN,CAACR,EAAD,EAAKQ,aAAL,CAhBM,EAiBN,CAACP,EAAD,EAAKO,8BAAL,CAjBM,EAkBN,CAACN,EAAD,EAAKM,kBAAL,CAlBM,EAmBN,CAACL,EAAD,EAAKK,yCAAL,CAnBM,EAoBN,CAACJ,EAAD,EAAKI,4CAAL,CApBM,EAqBN,CAACH,EAAD,EAAKG,2DAAL,CArBM;UAuBR,OAAOF,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QAxBTC,CAAAA;;AA6BAC,QAAAA,uCAAAA,mCAA4B1B,GAA5B0B;AAAAA,UAAAA;;;UACEzB,QAAQ,CACN,CAACC,EAAD,EAAKwB,aAAL,CADM,EAEN,CAACvB,EAAD,EAAKuB,UAAL,CAFM,EAGN,CAACtB,EAAD,EAAKsB,UAAL,CAHM,EAIN,CAACrB,EAAD,EAAKqB,MAAL,CAJM,EAKN,CAACpB,EAAD,EAAKoB,QAAL,CALM,EAMN,CAACnB,EAAD,EAAKmB,SAAL,CANM,EAON,CAAClB,EAAD,EAAKkB,SAAL,CAPM,EAQN,CAACjB,EAAD,EAAKiB,MAAL,CARM,EASN,CAAChB,EAAD,EAAKgB,QAAL,CATM,EAUN,CAACf,EAAD,EAAKe,kBAAL,CAVM,EAWN,CAACd,EAAD,EAAKc,UAAL,CAXM,EAYN,CAACb,EAAD,EAAKa,UAAL,CAZM,EAaN,CAACZ,EAAD,EAAKY,OAAL,CAbM,EAcN,CAACX,EAAD,EAAKW,OAAL,CAdM,EAeN,CAACV,EAAD,EAAKU,SAAL,CAfM,EAgBN,CAACT,EAAD,EAAKS,QAAL,CAhBM,EAiBN,CAACR,EAAD,EAAKQ,OAAL,CAjBM,EAkBN,CAACP,EAAD,EAAKO,OAAL,CAlBM,EAmBN,CAACN,EAAD,EAAKM,SAAL,CAnBM,EAoBN,CAACL,EAAD,EAAKK,QAAL,CApBM,EAqBN,CAACJ,EAAD,EAAKI,OAAL,CArBM;UAuBR,OAAOH,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QAxBTE,CAAAA;;AA4BAC,QAAAA,4CAAAA,wCAAiC3B,GAAjC2B;AAAAA,UAAAA;;;UACEC,KAAKC,eAAWC,WAAAA,CAAWC,CAAXD;UAChBE,gBAAgB,CACd,CAACC,CAAD,EAAIC,MAAAX,IAAAW,UAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;;YAASA,OAAAb,IAAAc,yBAAAA,CAAwBT,EAAxBS,CAATF,CAAAA,GAAAA,SAAAA,CAAAD,CAAJ,CADc,EAEd,CAACI,CAAD,EAAIJ,MAAAX,IAAAW,UAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;;YAASA,OAAAb,IAAAgB,gCAAAA,CAA+BX,EAA/BW,CAATJ,CAAAA,GAAAA,SAAAA,CAAAD,CAAJ,CAFc,EAGd,CAACM,CAAD,EAAIN,MAAAX,IAAAW,UAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;;YAASA,OAAAb,IAAAkB,0BAAAA,CAAyBb,EAAzBa,CAATN,CAAAA,GAAAA,SAAAA,CAAAD,CAAJ,CAHc,EAId,CAACQ,CAAD,EAAIR,MAAAX,IAAAW,UAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;;YAASA,OAAAb,IAAAoB,0BAAAA,CAAyBf,EAAzBe,CAATR,CAAAA,GAAAA,SAAAA,CAAAD,CAAJ,CAJc,EAKd,CAACU,CAAD,EAAIV,MAAAX,IAAAW,UAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;;YAASA,OAAAb,IAAAsB,iCAAAA,CAAgCjB,EAAhCiB,CAATV,CAAAA,GAAAA,SAAAA,CAAAD,CAAJ,CALc,EAMd,CAACH,CAAD,EAAIG,MAAAX,IAAAW,UAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;;YAASA,OAAAb,IAAAuB,uBAAAA,CAAsBlB,EAAtBkB,CAATX,CAAAA,GAAAA,SAAAA,CAAAD,CAAJ,CANc;UAQhB,OAAOX,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBgC,aAAzBR;QAVTG,CAAAA;;AAcAU,QAAAA,uCAAAA,mCAA4BrC,GAA5BqC;AAAAA,UAAAA;;;UACEpC,QAAQ,CACN,CAACgC,CAAD,EAAII,qGAAJ,CADM,EAEN,CAACC,CAAD,EAAID,kGAAJ,CAFM,EAGN,CAACG,CAAD,EAAIH,qGAAJ,CAHM,EAIN,CAACK,CAAD,EAAIL,2EAAJ,CAJM,EAKN,CAACO,CAAD,EAAIP,6EAAJ,CALM,EAMN,CAACN,CAAD,EAAIM,0IAAJ,CANM;UAQR,OAAOd,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QATTa,CAAAA;;AAaAE,QAAAA,8CAAAA,0CAAmCvC,GAAnCuC;AAAAA,UAAAA;;;UACEtC,QAAQ,CACN,CAACgC,CAAD,EAAIM,oFAAJ,CADM,EAEN,CAACD,CAAD,EAAIC,8EAAJ,CAFM,EAGN,CAACC,CAAD,EAAID,qFAAJ,CAHM,EAIN,CAACG,CAAD,EAAIH,2FAAJ,CAJM,EAKN,CAACK,CAAD,EAAIL,kFAAJ,CALM,EAMN,CAACR,CAAD,EAAIQ,uFAAJ,CANM;UAQR,OAAOhB,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QATTe,CAAAA;;AAaAE,QAAAA,wCAAAA,oCAA6BzC,GAA7ByC;AAAAA,UAAAA;;;UACExC,QAAQ,CACN,CAACgC,CAAD,EAAIQ,8EAAJ,CADM,EAEN,CAACH,CAAD,EAAIG,+CAAJ,CAFM,EAGN,CAACD,CAAD,EAAIC,gEAAJ,CAHM,EAIN,CAACC,CAAD,EAAID,sIAAJ,CAJM,EAKN,CAACG,CAAD,EAAIH,2CAAJ,CALM,EAMN,CAACV,CAAD,EAAIU,uEAAJ,CANM;UAQR,OAAOlB,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QATTiB,CAAAA;;AAaAE,QAAAA,wCAAAA,oCAA6B3C,GAA7B2C;AAAAA,UAAAA;;;UACE1C,QAAQ,CACN,CAACgC,CAAD,EAAIU,+DAAJ,CADM,EAEN,CAACL,CAAD,EAAIK,iEAAJ,CAFM,EAGN,CAACH,CAAD,EAAIG,gEAAJ,CAHM,EAIN,CAACD,CAAD,EAAIC,8DAAJ,CAJM,EAKN,CAACC,CAAD,EAAID,wEAAJ,CALM,EAMN,CAACZ,CAAD,EAAIY,kEAAJ,CANM;UAQR,OAAOpB,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QATTmB,CAAAA;;AAaAE,QAAAA,+CAAAA,2CAAoC7C,GAApC6C;AAAAA,UAAAA;;;UACE5C,QAAQ,CACN,CAACgC,CAAD,EAAIY,6EAAJ,CADM,EAEN,CAACP,CAAD,EAAIO,4EAAJ,CAFM,EAGN,CAACL,CAAD,EAAIK,8EAAJ,CAHM,EAIN,CAACH,CAAD,EAAIG,2EAAJ,CAJM,EAKN,CAACD,CAAD,EAAIC,+GAAJ,CALM,EAMN,CAACd,CAAD,EAAIc,sDAAJ,CANM;UAQR,OAAOtB,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QATTqB,CAAAA;QAaA/C,OAAAgD,qCAAAA,iCAA0B9C,GAA1B8C;AAAAA,UAAAA;;;UACE7C,QAAQ,CACN,CAACgC,CAAD,EAAIa,yHAAJ,CADM,EAEN,CAACR,CAAD,EAAIQ,4HAAJ,CAFM,EAGN,CAACN,CAAD,EAAIM,qIAAJ,CAHM,EAIN,CAACJ,CAAD,EAAII,yHAAJ,CAJM,EAKN,CAACF,CAAD,EAAIE,8HAAJ,CALM,EAMN,CAACf,CAAD,EAAIe,iIAAJ,CANM;UAQR,OAAOvB,IAAAC,qBAAAA,CAAoBxB,GAApB,EAAyBC,KAAzBuB;QATTsB,CAAAA;MAxKFhD,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>1717, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom_basic/name_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdomBasic\n      # エキゾチック名前表(D66)\n      # override\n      def mk_name_ex_table(num)\n        table = [\n          [11, \"モアイ／スイショウドクロ\"],\n          [12, \"チュパカブラ／ムベンベ\"],\n          [13, \"カンフー／インヤン\"],\n          [14, \"ブシドー／ミヤコ\"],\n          [15, \"チャンピオン／バービー\"],\n          [16, \"ウパニシャッド／ゾルゲ\"],\n          [22, \"デスマーチ／インテル\"],\n          [23, \"ゴッホ／ヴィクトリア\"],\n          [24, \"ゾンビ／オニャンコポン\"],\n          [25, \"ケロッパ／カルメン\"],\n          [26, \"オーバーキル／サシミ\"],\n          [33, \"ブッチャー／デヴィ\"],\n          [34, \"ブロンソン／マドンナ\"],\n          [35, \"ガイギャックス／エロイカ\"],\n          [36, \"好きな星の名前(スピカ,オリオン)\"],\n          [44, \"好きな武器の名前(エペ,フランベルジュ)\"],\n          [45, \"好きな動物の名前(イタチ,パグ)\"],\n          [46, \"好きな鉱物の名前(ルビィ,ヒスイ)\"],\n          [55, \"好きな言葉＋ドラゴン\"],\n          [56, \"好きな単語表で決定する\"],\n          [66, \"プレイヤーと同じ名前\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 新名前決定表\n      def mk_new_name_table\n        nick_table = \"1\"\n        name_table = \"1\"\n        # 新名前表\n        nick_n = @randomizer.roll_once(6)\n        name_n = @randomizer.roll_once(6)\n        d1 = @randomizer.roll_d66(D66SortType::ASC)\n        d2 = @randomizer.roll_d66(D66SortType::ASC)\n\n        # 二つ名分岐\n        if nick_n <= 1\n          nick_table = mk_nick_pr_table(d1)\n        elsif name_n <= 2\n          nick_table = mk_nick_fo_table(d1)\n        elsif name_n <= 3\n          nick_table = mk_nick_ou_table(d1)\n        elsif name_n <= 4\n          nick_table = mk_nick_ti_table(d1)\n        elsif name_n <= 5\n          nick_table = mk_nick_ph_table(d1)\n        else\n          nick_table = mk_nick_co_table(d1)\n        end\n\n        # 名前分岐\n        if name_n <= 1\n          name_table = mk_name_ar_table(d2)\n        elsif name_n <= 2\n          name_table = mk_name_fo_table(d2)\n        elsif name_n <= 3\n          name_table = mk_name_dn_table(d2)\n        elsif name_n <= 4\n          name_table = mk_name_pl_table(d2)\n        elsif name_n <= 5\n          name_table = mk_name_ma_table(d2)\n        else\n          name_table = mk_name_go_table(d2)\n        end\n\n        output = nick_table + name_table\n        debug(\"output\", output)\n        dice = \"\#{nick_n},\#{name_n},\#{d1},\#{d2}\"\n\n        return output, dice\n      end\n\n      # ことわざ系二つ名表\n      def mk_nick_pr_table(num)\n        table = [\n          [11, \"“九死に一生を得る”\"],\n          [12, \"“風前の灯火の”\"],\n          [13, \"“類は友を呼ぶ”\"],\n          [14, \"“性格がいい方の”\"],\n          [15, \"“三階に家なき”\"],\n          [16, \"“五分の理はある”\"],\n          [22, \"“危ない橋を渡る”\"],\n          [23, \"“バカって言った方がバカの”\"],\n          [24, \"“長いものに巻かれる”\"],\n          [25, \"“火の無いところの”\"],\n          [26, \"“あばたもえくぼの”\"],\n          [33, \"“将を射んとせばまず”\"],\n          [34, \"“氷山の一角の”\"],\n          [35, \"“木乃伊取りが木乃伊になる”\"],\n          [36, \"“一見の価値ありの”\"],\n          [44, \"“一日の長ある”\"],\n          [45, \"“遠くの親類より近くの”\"],\n          [46, \"“笑う門には福来る”\"],\n          [55, \"“花は桜木、人は”\"],\n          [56, \"“猫に小判の”\"],\n          [66, \"“（クラス名／ジョブ名）による（クラス名／ジョブ名）のための”\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 四字熟語系二つ名表\n      def mk_nick_fo_table(num)\n        table = [\n          [11, \"“自画自賛（の）”\"],\n          [12, \"“人畜無害（の）”\"],\n          [13, \"“不言実行（の）”\"],\n          [14, \"“痛快無比（の）”\"],\n          [15, \"“外柔内剛（の）”\"],\n          [16, \"“百戦錬磨（の）”\"],\n          [22, \"“前代未聞（の）”\"],\n          [23, \"“粉骨砕身（の）”\"],\n          [24, \"“天真爛漫（の）”\"],\n          [25, \"“暴飲暴食（の）”\"],\n          [26, \"“意志薄弱（の）”\"],\n          [33, \"“慇懃無礼（の）”\"],\n          [34, \"“沈魚落雁（の）”\"],\n          [35, \"“波乱万丈（の）”\"],\n          [36, \"“二束三文（の）”\"],\n          [44, \"“行雲流水（の）”\"],\n          [45, \"“驚天動地（の）”\"],\n          [46, \"“破邪顕正（の）”\"],\n          [55, \"“以心伝心（の）”\"],\n          [56, \"“博覧強記（の）”\"],\n          [66, \"“殺人事件（の）”\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 外見系二つ名表\n      def mk_nick_ou_table(num)\n        table = [\n          [11, \"“もふもふの”\"],\n          [12, \"“裸の”\"],\n          [13, \"“猫耳の”\"],\n          [14, \"“歩くと音がする”\"],\n          [15, \"“緑髪の”\"],\n          [16, \"“黄金（の）”\"],\n          [22, \"“羽根つき（の）”\"],\n          [23, \"“小さな”\"],\n          [24, \"“蛇手の”\"],\n          [25, \"“鉤シッポの”\"],\n          [26, \"“ぎざぎざの”\"],\n          [33, \"“輝ける”\"],\n          [34, \"“角持ち（の）”\"],\n          [35, \"“とんがり帽子の”\"],\n          [36, \"“青ざめた”\"],\n          [44, \"“赤目の”\"],\n          [45, \"“黒衣の”\"],\n          [46, \"“ねじれ声の”\"],\n          [55, \"“銀の腕”\"],\n          [56, \"“長靴下の”\"],\n          [66, \"“ぬるぬるの”\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 称号系二つ名表\n      def mk_nick_ti_table(num)\n        table = [\n          [11, \"“（王国名）の星”\"],\n          [12, \"“（王国名）の独眼竜”\"],\n          [13, \"“（王国名）の麒麟児”\"],\n          [14, \"“（王国名）の虎”\"],\n          [15, \"“（王国名）のマムシ”\"],\n          [16, \"“（王国名）１Ｄ６天王”\"],\n          [22, \"“（王国名）１Ｄ６傑”\"],\n          [23, \"“（王国名）１Ｄ６銃士”\"],\n          [24, \"“（王国名）１０＋１Ｄ６神将”\"],\n          [25, \"“（王国名）２Ｄ６（兄弟／姉妹）”\"],\n          [26, \"“（王国名）２Ｄ６賢人”\"],\n          [33, \"“あの（クラス名／ジョブ名）”\"],\n          [34, \"“最後の（クラス名／ジョブ名）”\"],\n          [35, \"“メカ（クラス名／ジョブ名）”\"],\n          [36, \"“殺人（クラス名／ジョブ名）”\"],\n          [44, \"“カリスマ（クラス名／ジョブ名）”\"],\n          [45, \"“超級（クラス名／ジョブ名）”\"],\n          [46, \"“攻め（クラス名／ジョブ名）”\"],\n          [55, \"“スタイリッシュ（クラス名／ジョブ名）”\"],\n          [56, \"“大（クラス名／ジョブ名）”\"],\n          [66, \"“鬼（クラス名／ジョブ名）”\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 名文句系二つ名表\n      def mk_nick_ph_table(num)\n        table = [\n          [11, \"“世界が嫉妬する”\"],\n          [12, \"“うまい、うますぎる”\"],\n          [13, \"“２４時間戦える”\"],\n          [14, \"“脱いでもすごい”\"],\n          [15, \"“ピカピカの１年生”\"],\n          [16, \"“どうあがいても絶望の”\"],\n          [22, \"“ダメ絶対の”\"],\n          [23, \"“すべての王国を過去にする”\"],\n          [24, \"“１００人乗っても大丈夫な”\"],\n          [25, \"“綺麗なおねえさんが好きな”\"],\n          [26, \"“食う寝る遊ぶの”\"],\n          [33, \"“かわいいは正義の”\"],\n          [34, \"“それにつけても”\"],\n          [35, \"“お口の恋人”\"],\n          [36, \"“やめられない止まらない”\"],\n          [44, \"“半分はやさしさの”\"],\n          [45, \"“国民的美少女”\"],\n          [46, \"“プライスレスの”\"],\n          [55, \"“驚きの白さの”\"],\n          [56, \"“楽器のマークの”\"],\n          [66, \"“パンツじゃないから恥ずかしくない”\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # かっこいい系二つ名表\n      def mk_nick_co_table(num)\n        table = [\n          [11, \"“（王国名／氷）の牙”\"],\n          [12, \"“（王国名／不可視）の猟犬”\"],\n          [13, \"“（王国名／暴虐）の女神”\"],\n          [14, \"“（王国名／無限）の境界”\"],\n          [15, \"“（王国名／偽り）の救世主”\"],\n          [16, \"“（王国名／闇）の扉”\"],\n          [22, \"“（王国名／暁）の凶星”\"],\n          [23, \"“（王国名／災禍）の中心”\"],\n          [24, \"“（王国名／始まり）の記憶”\"],\n          [25, \"“（王国名／絶対）の歌声”\"],\n          [26, \"“（王国名／星霜）の死神”\"],\n          [33, \"“（王国名／不確定）の隠者”\"],\n          [34, \"“（王国名／冥府）の番人”\"],\n          [35, \"“（王国名／深淵）の使途”\"],\n          [36, \"“（王国名／罪）の華”\"],\n          [44, \"“（王国名／終末）の翼”\"],\n          [45, \"“（王国名／絶望）の匠”\"],\n          [46, \"“（王国名／鮮血）の芸術家”\"],\n          [55, \"“（王国名／流星）の魔剣”\"],\n          [56, \"“（王国名／漆黒）の堕天使”\"],\n          [66, \"“（王国名／無貌）の悪夢”\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 芸術系名前表(D66)\n      def mk_name_ar_table(num)\n        table = [\n          [11, \"コーラス／メロディ\"],\n          [12, \"シタール／コト\"],\n          [13, \"トロンボーン／ティンパニ\"],\n          [14, \"マーチ／セレナーデ\"],\n          [15, \"ソロ／オーケストラ\"],\n          [16, \"パッソ／プリマ\"],\n          [22, \"モノローグ／アポローズ\"],\n          [23, \"スクリプト／カメリーノ\"],\n          [24, \"アール／エピカ\"],\n          [25, \"ラインズ／ムジカ\"],\n          [26, \"トルバドール／リリカ\"],\n          [33, \"ノベル／ラマーン\"],\n          [34, \"クリーミ／ストーリア\"],\n          [35, \"エッセイ／メモワール\"],\n          [36, \"ジャケット／コロフォン\"],\n          [44, \"デビュー／セーヌ\"],\n          [45, \"タンゴ／バル\"],\n          [46, \"イーゼル／パレット\"],\n          [55, \"カンバス／タトゥー\"],\n          [56, \"ウッドカット／キラーミカ\"],\n          [66, \"ポートレイト／パノラマ\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 食べ物系名前表(D66)\n      def mk_name_fo_table(num)\n        table = [\n          [11, \"ダージリン／マンデリン\"],\n          [12, \"コニャック／ピーノ\"],\n          [13, \"グラス／テキーラ\"],\n          [14, \"ハングオーバー／リキュール\"],\n          [15, \"ブレッド／プレッツェル\"],\n          [16, \"バケット／コロネ\"],\n          [22, \"クロワッサン／ヤムチャ\"],\n          [23, \"ヤキソバ／パッタイ\"],\n          [24, \"ニョッキ／ペンネ\"],\n          [25, \"ハニー／メイプル\"],\n          [26, \"ガトー／フラン\"],\n          [33, \"ジュレ／ソルベ\"],\n          [34, \"リゾット／チマキ\"],\n          [35, \"フリット／テンプラ\"],\n          [36, \"カルビ／ハラミ\"],\n          [44, \"ポージョ／ユーリンチー\"],\n          [45, \"アイスバイン／イベリコ\"],\n          [46, \"ブルスト／キシュカ\"],\n          [55, \"ドリアン／キウィ\"],\n          [56, \"ココ／プラム\"],\n          [66, \"ガリガリ／ポテチ\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      # 日用品系名前表(D66)\n      def mk_name_dn_table(num)\n        table = [\n          [11, \"ファイバー／シルク\"],\n          [12, \"ジーンズ／キュロット\"],\n          [13, \"ガーター／ソックス\"],\n          [14, \"クラヴァッテ／スカーフ\"],\n          [15, \"サンダル／ハイヒール\"],\n          [16, \"リング／ブローチ\"],\n          [22, \"ボタン／リカーモ\"],\n          [23, \"シュピーゲル／ルージュ\"],\n          [24, \"オーデコロン／マニキュア\"],\n          [25, \"シルクハット／サリー\"],\n          [26, \"ソープ／コーム\"],\n          [