 \"クピド（上級p121）\"],\n          [612, \"クピド（上級p121）\"],\n          [613, \"季士（大冒険p113）\"],\n          [614, \"季士（大冒険p113）\"],\n          [615, \"三羽ガラス（基本p201）\"],\n          [616, \"三羽ガラス（基本p201）\"],\n          [621, \"エンゼルヘアー（上級p121）\"],\n          [622, \"エンゼルヘアー（上級p121）\"],\n          [623, \"紙鳶（大冒険p113）\"],\n          [624, \"紙鳶（大冒険p113）\"],\n          [625, \"雲神（基本p201）\"],\n          [626, \"雲神（基本p201）\"],\n          [631, \"鉄砲魚（基本p204）\"],\n          [632, \"鉄砲魚（基本p204）\"],\n          [633, \"植木魚（大冒険p118）\"],\n          [634, \"植木魚（大冒険p118）\"],\n          [635, \"河豚提灯（p141）\"],\n          [636, \"河豚提灯（p141）\"],\n          [641, \"エルフ（基本p205）\"],\n          [642, \"エルフ（基本p205）\"],\n          [643, \"人魚（上級p125）\"],\n          [644, \"人魚（上級p125）\"],\n          [645, \"イカロス（基本p205）\"],\n          [646, \"イカロス（基本p205）\"],\n          [651, \"河童（蟇本p205）\"],\n          [652, \"河童（蟇本p205）\"],\n          [653, \"魚人（基本p205）\"],\n          [654, \"魚人（基本p205）\"],\n          [655, \"鰐人（大冒険p119）\"],\n          [656, \"鰐人（大冒険p119）\"],\n          [661, \"水霊（上級p125）\"],\n          [662, \"水霊（上級p125）\"],\n          [663, \"海馬（上級p125）\"],\n          [664, \"海馬（上級p125）\"],\n          [665, \"まぼろし蛤（上級p125）\"],\n          [666, \"まぼろし蛤（上級p125）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_demand_table(num)\n        table = [\n          [1, \"疫病の流行。「医薬品」か「著作物」なら〈予算〉を2MG獲得。「嗜好品」か「道具」なら維持費を1MG上昇。「資源」なら維持費を2MG上昇。\"],\n          [2, \"近くで新しい王国が興る！「道具」か「資源」なら〈予算〉を1MG獲得。「嗜好品」か「著作物」なら維持費を1MG上昇。\"],\n          [3, \"各国で供給過多。ものが溢れている！「嗜好品」なら〈予算〉を1MG獲得。「食品」なら維持費を1MG上昇。\"],\n          [4, \"周囲の産業が順調。「食品」か「著作物」なら〈予算〉を2MG獲得。「嗜好品」か「道具」なら〈予算〉を1MG獲得。\"],\n          [5, \"どこかで戦争の予感？「資源」か「医薬品」なら〈予算〉を2MG獲得。「食品」か「道具」か「資源」なら〈予算〉を1MG獲得。「著作物」なら維持費を2MG上昇。\"],\n          [6, \"平穏な日々が続く。「嗜好品」なら〈予算〉を3MG獲得。「著作物」なら〈予算〉を2MG獲得。「食品」か「道具」か「資源」なら〈予算〉を1MG獲得。「医薬品」なら維持を1MG上昇。\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def get_demand_table(level)\n        output = \"\"\n        @dice = []\n        @count = [0, 0, 0, 0, 0, 0]\n        (1..level).each do\n          num = @randomizer.roll_once(6)\n          @dice.push(num)\n          @count[num - 1] += 1\n        end\n        (1..6).each do |idx|\n          if @count[idx - 1] > 0\n            output += \"\\n\" unless output.empty?\n            output += mk_demand_table(idx)\n          end\n\n          if level >= 3\n            if idx == 1\n              if @count[idx - 1] > 1\n                output += \" ＞ 維持費\#{level}MG上昇。\"\n              end\n            else\n              if @count[idx - 1] > 1\n                output += \" ＞ \#{level}MG獲得。\"\n              end\n            end\n          end\n        end\n        return output, @dice.sort.join(\",\")\n      end\n\n      def mk_race_name_character_table(num)\n        table = [\n          [202, \"男\"],\n          [203, \"木\"],\n          [204, \"晶\"],\n          [205, \"氷\"],\n          [206, \"指\"],\n          [207, \"銀\"],\n          [208, \"舌\"],\n          [209, \"鼠\"],\n          [210, \"迷\"],\n          [211, \"溶\"],\n          [212, \"新\"],\n          [302, \"音\"],\n          [303, \"葉\"],\n          [304, \"壁\"],\n          [305, \"土\"],\n          [306, \"首\"],\n          [307, \"桃\"],\n          [308, \"汁\"],\n          [309, \"牛\"],\n          [310, \"怒\"],\n          [311, \"楽\"],\n          [312, \"夕\"],\n          [402, \"都\"],\n          [403, \"花\"],\n          [404, \"砂\"],\n          [405, \"風\"],\n          [406, \"鼻\"],\n          [407, \"緑\"],\n          [408, \"骨\"],\n          [409, \"虎\"],\n          [410, \"柔\"],\n          [411, \"高\"],\n          [412, \"春\"],\n          [502, \"旅\"],\n          [503, \"蔦\"],\n          [504, \"門\"],\n          [505, \"泉\"],\n          [506, \"口\"],\n          [507, \"黒\"],\n          [508, \"毛\"],\n          [509, \"兎\"],\n          [510, \"寒\"],\n          [511, \"太\"],\n          [512, \"夏\"],\n          [602, \"詩\"],\n          [603,