get_race_name_character_table(count)\n        output = \"\"\n        total_n = \"\"\n        (1..count).each do\n          @total = [@randomizer.roll_barabara(2, 6).sum(), @randomizer.roll_barabara(2, 6).sum()]\n          total_n += \",\" unless total_n.empty?\n          total_n += @total.join(\",\")\n          num = @total[0] * 100 + @total[1]\n          output += mk_race_name_character_table(num)\n        end\n        return output, total_n\n      end\n\n      def mk_currency_material_table(num)\n        table = [\n          [2, \"そのほかの材質\"],\n          [3, \"人貨\"],\n          [4, \"天貨\"],\n          [5, \"獣貨\"],\n          [6, \"紙幣\"],\n          [7, \"金貨幣\"],\n          [8, \"石貨\"],\n          [9, \"食貨\"],\n          [10, \"深貨\"],\n          [11, \"魔貨\"],\n          [12, \"そのほかの材質\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table2(num)\n        table = [\n          [1, \"葉っぱ\"],\n          [2, \"人の感情を結晶化したもの\"],\n          [3, \"矢じり\"],\n          [4, \"剣\"],\n          [5, \"楽器\"],\n          [6, \"眼鏡\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table3(num)\n        table = [\n          [1, \"美人\"],\n          [2, \"農民\"],\n          [3, \"職人\"],\n          [4, \"役人\"],\n          [5, \"戦士\"],\n          [6, \"小鬼\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table4(num)\n        table = [\n          [1, \"羽毛\"],\n          [2, \"皮膜\"],\n          [3, \"くちばし\"],\n          [4, \"天使の骨\"],\n          [5, \"時計\"],\n          [6, \"雪や氷\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table5(num)\n        table = [\n          [1, \"猫\"],\n          [2, \"犬\"],\n          [3, \"羊\"],\n          [4, \"牛\"],\n          [5, \"キンギョ\"],\n          [6, \"ウマトカゲ\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table6(num)\n        table = [\n          [1, \"いわゆるお礼\"],\n          [2, \"切手\"],\n          [3, \"証文や契約書\"],\n          [4, \"手紙\"],\n          [5, \"宝くじ\"],\n          [6, \"物語の断片\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table7(num)\n        table = [\n          [1, \"金貨\"],\n          [2, \"銀貨\"],\n          [3, \"銅貨\"],\n          [4, \"鉄貨\"],\n          [5, \"白金貨\"],\n          [6, \"プルトニウム貨\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table8(num)\n        table = [\n          [1, \"巨大な石片\"],\n          [2, \"陶貨\"],\n          [3, \"輝石\"],\n          [4, \"つるつるに磨いた小石\"],\n          [5, \"変わった色の砂\"],\n          [6, \"星の粒\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table9(num)\n        table = [\n          [1, \"お米\"],\n          [2, \"パン\"],\n          [3, \"卵\"],\n          [4, \"お酒\"],\n          [5, \"バナナ\"],\n          [6, \"マヨネーズ\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table10(num)\n        table = [\n          [1, \"珊瑚\"],\n          [2, \"貝殻\"],\n          [3, \"鱗\"],\n          [4, \"深人の骨\"],\n          [5, \"甲羅\"],\n          [6, \"塩\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table11(num)\n        table = [\n          [1, \"宗教的シンボル\"],\n          [2, \"サイコロ\"],\n          [3, \"人形\"],\n          [4, \"生き血\"],\n          [5, \"思い出の品\"],\n          [6, \"迷核だったものの欠片\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_currency_material_table12(num)\n        table = [\n          [1, \"スプーンやフォーク\"],\n          [2, \"お皿\"],\n          [3, \"鍵\"],\n          [4, \"布\"],\n          [5, \"糸\"],\n          [6, \"針\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def get_currency_material_table(num1, num2)\n        output = mk_currency_material_table(num1) + \":\"\n\n        case num1\n        when 2\n          output += mk_currency_material_table2(num2)\n        when 3\n          output += mk_currency_material_table3(num2)\n        when 4\n          output += mk_currency_material_table4(num2)\n        when 5\n          output += mk_currency_material_table5(num2)\n        when 6\n          output += mk_currency_material_table6(num2)\n        when 7\n          output += mk_currency_material_table7(num2)\n        when 8\n          output += mk_currency_material_table8(num2)\n        when 9\n          output += mk_currency_material_table9(num2)\n        when 10\n          output += mk_currency_material_table10(num2)\n        when 11\n          output += mk_currency_material_table11(num2)\n        when 12\n          output += mk_currency_material_table12(num2)\n        end\n        return output\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdomBasic>", "DiceTable::Table", "DiceTable", "new", "DiceTable::D66Table", "D66SortType::ASC", "D66SortType", "11", "12", "13", "14", "15", "16", "22", "23", "24", "25", "26", "33", "34", "35", "36", "44", "45", "46", "55", "56", "66", "freeze", "mk_guardian_constellation_table", "num", "table", "111", "112", "113", "114", "115", "116", "121", "122", "123", "124", "125", "126", "131", "132", "133", "134", "135", "136", "141", "142", "143", "144", "145", "146", "151", "152", "153", "154", "155", "156", "161", "162", "163", "164", "165", "166", "211", "212", "213", "214", "215", "216", "221", "222", "223", "224", "225", "226", "231", "232", "233", "234", "235", "236", "241", "242", "243", "244", "245", "248", "251", "252", "253", "254", "255", "256", "261", "262", "263", "264", "265", "266", "311", "312", "313", "314", "315", "316", "321", "322", "323", "324", "325", "326", "331", "332", 