line=>2223, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/meikyu_kingdom_basic/randr236_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class MeikyuKingdomBasic\n      RR236_TABLES = {\n        \"FCNT\" => DiceTable::D66Table.new(\n          \"四字熟語系二つ名表\",\n          D66SortType::ASC,\n          {\n            11 => \"人類最強（の）\",\n            12 => \"天下無双（の）\",\n            13 => \"電光石火（の）\",\n            14 => \"冷静沈着（の）\",\n            15 => \"星河一天（の）\",\n            16 => \"幽玄美麗（の）\",\n            22 => \"義理人情（の）\",\n            23 => \"堅忍不抜（の）\",\n            24 => \"忠勇義烈（の）\",\n            25 => \"風林火山（の）\",\n            26 => \"破顔一笑（の）\",\n            33 => \"破顔一笑（の）\",\n            34 => \"一騎当千（の）\",\n            35 => \"阿鼻叫喚（の）\",\n            36 => \"一蓮托生（の）\",\n            44 => \"一期一会（の）\",\n            45 => \"天涯孤独（の）\",\n            46 => \"鬼哭啾々（の）\",\n            55 => \"一宿一飯（の）\",\n            56 => \"軽挙妄動（の）\",\n            66 => \"贅沢三昧（の）\",\n          }\n        ),\n        \"ASNT\" => DiceTable::D66Table.new(\n          \"代入命名表\",\n          D66SortType::ASC,\n          {\n            11 => \"［好きなもの／嫌いなもの］［呼び名表］\",\n            12 => \"［行動表］が取り柄の\",\n            13 => \"宮廷に［行動表］をうながす\",\n            14 => \"二度と［行動表］しない\",\n            15 => \"ベテラン［行動表］請負人\",\n            16 => \"絶対［行動表］マン／ウーマン\",\n            22 => \"［好きなもの／嫌いなもの］警察\",\n            23 => \"［好きなもの／嫌いなもの］と生きる\",\n            24 => \"［呼び名表］の中の［同じ単語の繰り返し］\",\n            25 => \"［用語表］を呼ぶ［呼び名表／称号表］\",\n            26 => \"王国［行動表］部部長\",\n            33 => \"［用語表／行動表］省幹部\",\n            34 => \"迷宮三大［呼び名表］の一人\",\n            35 => \"猛き［用語表］の勇者\",\n            36 => \"一級［行動表］資格所持者\",\n            44 => \"［形容表］［行動表］の使い手\",\n            45 => \"過激な［用語表／行動表］主義者\",\n            46 => \"［行動表／好きなもの／嫌いなもの］界の大物\",\n            55 => \"［形容表］［PCの名前］構文\",\n            56 => \"特殊［行動表］技能士\",\n            66 => \"［用語表］を［行動表］する影\",\n          }\n        ),\n        \"FPNT\" => DiceTable::D66Table.new(\n          \"名文句系二つ名表\",\n          D66SortType::ASC,\n          {\n            11 => \"またお前か（の）\",\n            12 => \"もう死んでいる\",\n            13 => \"訴訟も辞さない\",\n            14 => \"ですよねー（の）\",\n            15 => \"そんなに悪くなかった\",\n            16 => \"お値段以上（の）\",\n            22 => \"ファイト一発（の）\",\n            23 => \"それでもやってない\",\n            24 => \"テストに出る\",\n            25 => \"まるで成長していない\",\n            26 => \"幸せならOKの\",\n            33 => \"希望を乗せて走る\",\n            34 => \"誰もお前を愛さない\",\n            35 => \"すぐおいしい\",\n            36 => \"毎日が新しい\",\n            44 => \"本気になった\",\n            45 => \"あなたとコンビに\",\n            46 => \"50MG欲しい\",\n            55 => \"またしても何も知らない\",\n            56 => \"マジでこれの\",\n            66 => \"めっちゃ厳つい\",\n          }\n        ),\n      }.freeze\n\n      def mk_terminology_table(num)\n        # 用語表\n        table = [\n          [11, \"災厄／不幸（の）\"],\n          [12, \"爆笑／哀切／憤怒（の）\"],\n          [13, \"流星／疾風／光速（の）\"],\n          [14, \"狂乱／暴虐／殺戮（の）\"],\n          [15, \"稲妻／熱血（の）\"],\n          [16, \"純白／灰色／漆黒（の）\"],\n          [22, \"絶対／究極／至高（の）\"],\n          [23, \"迷宮／世界／鉄（の）\"],\n          [24, \"天階／深階（の）\"],\n          [25, \"斬撃／打撃／衝撃（の）\"],\n          [26, \"体制／革新（の）\"],\n          [33, \"平和／神聖／自己防衛（の）\"],\n          [34, \"男装／女装（の）\"],\n          [35, \"マヨネーズ／じゃがいも（の）\"],\n          [36, \"増税／権益（の）\"],\n          [44, \"星術／召喚／科学（の）\"],\n          [45, \"百獣／死神／異形（の）\"],\n          [46, \"最強／万能（の）\"],\n          [55, \"お祭り／平民／仮面（の）\"],\n          [56, \"神秘／幻（の）\"],\n          [66, \"未来／希望（の）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_behavior_table(num)\n        # 行動表\n        table = [\n          [11, \"建国（の）\"],\n          [12, \"休憩（の）\"],\n          [13, \"捜索（の）\"],\n          [14, \"攻撃（の）\"],\n          [15, \"号令（の）\"],\n          [16, \"集中（の）\"],\n          [22, \"支援（の）\"],\n          [23, \"移動（の）\"],\n          [24, \"取引（の）\"],\n          [25, \"交渉（の）\"],\n          [26, \"視察（の）\"],\n          [33, \"計画（の）\"],\n          [34, \"建設（の）\"],\n          [35, \"遭遇（の）\"],\n          [36, \"協調行動（の）\"],\n          [44, \"補助（の）\"],\n          [45, \"情報収集（の）\"],\n          [46, \"逃走（の）\"],\n          [55, \"割り込み（の）\"],\n          [56, \"貿易（の）\"],\n          [66, \"滅亡（の）\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_descriptive_table(num)\n        # 形容表\n        table = [\n          [11, \"闇に潜む\"],\n          [12, \"遥かなる\"],\n          [13, \"百年に一度の\"],\n          [14, \"笑わない\"],\n          [15, \"燃える\"],\n          [16, \"彷徨う\"],\n          [22, \"歌う\"],\n          [23, \"破滅を呼ぶ\"],\n          [24, \"人を喰った\"],\n          [25, \"ついてない\"],\n          [26, \"国民的\"],\n          [33, \"美しき\"],\n          [34, \"七つの顔を持つ\"],\n          [35, \"眠れる\"],\n          [36, \"優しい\"],\n          [44, \"もっとも神に近い\"],\n          [45, \"踊る\"],\n          [46, \"虫愛ずる\"],\n          [55, \"死せる\"],\n          [56, \"早すぎる\"],\n          [66, \"親愛なる\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_rr236_name_table(num)\n        # 呼び名表\n        table = [\n          [11, \"男／女\"],\n          [12, \"詩人／俳人\"],\n          [13, \"王／王者／女王\"],\n          [14, \"閣下／殿下\"],\n          [15, \"将軍／宰相\"],\n          [16, \"画伯／絵師\"],\n          [22, \"おじさん／おばさん\"],\n          [23, \"暴れん坊／豪傑\"],\n          [24, \"美丈夫／麗人\"],\n          [25, \"哲人／賢者\"],\n          [26, \"眼鏡\"],\n          [33, \"イケメン／美女\"],\n          [34, \"鉄人／巨人\"],\n          [35, \"英雄／魔王\"],\n          [36, \"支配者／主\"],\n          [44, \"ヤンキー／ギャル\"],\n          [45, \"頭脳／脳細胞\"],\n          [46, \"戦士／ファイター\"],\n          [55, \"父／母\"],\n          [56, \"太夫／役者\"],\n          [66, \"貴公子／令嬢\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_title_table(num)\n        # 称号表\n        table = [\n          [11, \"お坊ちゃま／お嬢様\"],\n          [12, \"申し子／落とし子\"],\n          [13, \"神／神様\"],\n          [14, \"天才／異端児\"],\n          [15, \"爆弾／爆発\"],\n          [16, \"超人\"],\n          [22, \"紳士／乙女\"],\n          [23, \"恐怖／悪夢\"],\n          [24, \"天使／悪魔\"],\n          [25, \"魂／権化\"],\n          [26, \"神童／新星\"],\n          [33, \"王子／王女\"],\n          [34, \"劇場／舞台\"],\n          [35, \"伝説／道\"],\n          [36, \"鬼／怪物\"],\n          [44, \"君／姫\"],\n          [45, \"帝／皇帝／女皇帝\"],\n          [46, \"名人／達人\"],\n          [55, \"信者／教徒\"],\n          [56, \"業者／界隈\"],\n          [66, \"斬り／殺し\"],\n        ]\n        return get_table_by_number(num, table)\n      end\n\n      def mk_combination_nickname_table()\n        output = \"\"\n        num1 = @randomizer.roll_once(6)\n        num2 = @randomizer.roll_d66(D66SortType::ASC)\n        num3 = @randomizer.roll_d66(D66SortType::ASC)\n        @total = [num1, num2, num3]\n        case num1\n        when 1\n          output = mk_terminology_table(num2) + \"、\" + mk_rr236_name_table(num3)\n        when 2\n          output = mk_terminology_table(num2) + \"、\" + mk_title_table(num3)\n        when 3\n          output = mk_behavior_table(num2) + \"、\" + mk_rr236_name_table(num3)\n        when 4\n          output = mk_behavior_table(num2) + \"、\" + mk_title_table(num3)\n        when 5\n          output = mk_descriptive_table(num2) + \"、\" + mk_rr236_name_table(num3)\n        when 6\n          output = mk_descriptive_table(num2) + \"、\" + mk_title_table(num3)\n        end\n        return output, @total.join(\",\")\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdomBasic>", "DiceTable::D66Table", "DiceTable", "new", "D66SortType::ASC", "D66SortType", "11", "12", "13", "14", "15", "16", "22", "23", "24", "25", "26", "33", "34", "35", "36", "44", "45", "46", "55", "56", "66", "freeze", "mk_terminology_table", "num", "table", "self", "get_table_by_number", "mk_behavior_table", "mk_descriptive_tabl