ム 基本ルールブック'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'めいきゆうきんくたむきほんるうるふつく'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~INFO_MESSAGE_TEXT\n          ・判定　(nMK+m)\n          　n個のD6を振って大きい物二つだけみて達成値を算出します。修正mも可能です。\n          　絶対成功と絶対失敗も自動判定します。\n          ・各種表\n          　・休憩表：才覚 TBT／魅力 CBT／探索 SBT／武勇 VBT\n                     お祭り FBT／空振り EBT／全体 WBT／カップル LBT\n                     お食事 FDBT\n          　・ハプニング表：才覚 THT／魅力 CHT／探索 SHT／武勇 VHT\n          　・視察表 RT／情報収集表 IG／ランダムマップ選択表 RMS\n          　・痛打表 CAT／致命傷表 FWT／戦闘ファンブル表 CFT\n          　・道中表 TT／交渉表 NT／相場表 MPT／王国災厄表 KDT／王国変動表 KCT\n          　・感情表 ET／好意表 FET／敵意表 HET\n          　・お宝表１／２／３／４／５ T1T／T2T／T3T／T4T／T5T\n          　・特殊遭遇表 SE\n          　　　上級：人工 ARN／水域 WEN／自然 NEN／洞窟 CEN／天空 SEN／異界 OEN\n          　・他国との関係表 ORT\n          ・潜在能力：スキル決定表 SDT\n          　　基本：肉弾 BUS／射撃 SHS／星術 ASS／召喚 SUS／科学 SCS\n          　　　　　迷宮 LAS／交渉 NES／便利 COS／芸能 ENS／道具 TOS\n          　　　　　一般 GES\n          　　上級：肉弾 ABUS／射撃 ASHS／星術 AASS／召喚 ASUS／科学 ASCS\n          　　　　　迷宮 ALAS／交渉 ANES／便利 ACOS／芸能 AENS／道具 ATOS\n          ・アイテム関連（上級不使用の場合、カッコ書きのものを使用して下さい）\n          　・コモンアイテムランダム決定表　CIR\n          　　　コモンアイテム表：武具 WIT／生活 LIT／回復 RIT／探索 SIT\n          　・レア武具アイテムランダム決定表　RWIR／レア一般アイテムランダム決定表　RUIR（上級込）\n          　　　レアアイテム表：基本武具 NRWT／基本一般 NRUT／上級武具 ARWT／上級一般 ARUT\n          　・デヴァイスファクトリー DFTx (xは特性の個数)\n          ・王国人物作成関連\n          　・王国名決定表１／２／３ KNT1／KNT2／KNT3\n          　・王国環境表 KET：技術 TET／国風 NST／資源 RET／人材 HRT／施設 FAT／血族 BLT\n          　・名前表 NAMEx (xは個数)\n          　　　名前A NAMEA／名前B NAMEB／エキゾチック NAMEEX／ファンタジック NAMEFA\n          　・新名前表 NNAMEx (xは個数)\n          　　　芸術 NMAR／食べ物 NMFO／日用品 NMDN／地名 NMPL／機械 NMMA／神様 NMGO\n          　・単語表１／２／３／４　WORD1／WORD2／WORD3／WORD4\n          　・生まれ決定表 BDT／生まれ表：才覚 TBO／魅力 CBO／探索 SBO／武勇 VBO\n          　・初期装備表 IEQ\n        　・地名決定表　PNTx (xは個数)／迷宮風景表 MLTx (xは個数)\n          ・百万世界AtoZ関連\n          　・ご祝儀表 GIFT\n          　・ニュース表 NWST\n          　・王国ハプニング表 KDHT\n          　・王国試練表 KDTT\n          　・騎士道表 CHVT\n          　・儀式表 RITT\n          　・限定表 LIMT\n          　・固有の文化表 UNCT\n          　・後世の評価表 POET\n          　・高レベル特殊遭遇表 KSET\n          　・死霊の日々表 DODT\n          　・事件名表1／2 INT1／INT2\n          　・守護星座表 GUCT\n          　・需要表 DEMTx (x:名物レベル)\n          　・小鬼と一緒表 WLDT\n          　・侵略ハプニング表 INHT\n          　・新・情報収集表 NIGT\n          　・人種特徴表／人種名文字表 RACT／RNCTx (x:文字数)\n          　・迷宮化現象表／人体迷宮化表 HBLT／LAPT\n          　・勢力表 POWT\n          　・中立特殊遭遇表 NSET\n          　・超協調行動表 ECBT\n          　・通貨外見表／通貨材質表／通貨名称表 CUAT／CUMT／CUNT\n          　・天候表 WEAT\n          　・毒の追加効果表 PAET\n          　・媒体表 MEDT\n          　・反応表／民の反応表 REAT／PRET\n          　・遍歴表 HIST\n          　・由来表 ORIT\n          　・誘致表 ATRT\n          　・妖精の悪戯表 FAMT\n          ・R&R236関連\n          　・四字熟語系二つ名表／代入命名表／組み合わせ系二つ名表／名文句系二つ名表 FCNT／ASNT／CMNT／FPNT\n          　・形容表／用語表／行動表／呼び名表／称号表 DEST／TRMT／BEHT／NAMT／TTLT\n          ・旅する王国と無名階域関連\n          　・サブキャラクター反応表 CSRT\n          　・スキルグループ表 KSGT\n          　・ダイナマイト帝国:休憩表／特殊遭遇表／二つ名表／名前表 DRET／DSET／DNNT／DNAT\n          　・ハグルマ資本主義神聖共和国:休憩表／特殊遭遇表／二つ名表／名前表 HRET／HSET／HNNT／HNAT\n          　・メトロ汗国:休憩表／特殊遭遇表／二つ名表／名前表 MRET／MSET／MNNT／MNAT\n          　・千年王朝:休憩表／特殊遭遇表／二つ名表／名前表 TRET／TSET／TNNT／TNAT\n          　・遠征王国変動表／遠征道中表 EKCT／EXITx (x:修正)\n          　・候補生背景表／職長背景表 CABT／FOBT\n          　・上級ジョブ表・甲／乙 AJTA／AJTB\n          　・深階休憩表／特殊遭遇表 KART／KAET\n          　・天階休憩表／特殊遭遇表 TERT／TEET\n          　・星の階休憩表 HKRT\n          　・装備決定表 EQDT\n          　・大冒険時代表 GART\n          　・燃料表 FUET\n          　・反乱表 RBLT\n          　・旅する王国環境表／王国名決定表1／王国名決定表2／王国名決定表3 TKET／TKNT1／TKNT2／TKNT3\n          　・列強経歴表 GPHT\n         ・D66ダイスあり\n      INFO_MESSAGE_TEXT\n\n      register_prefix(\n        '\\d+MK', '\\d+R6',\n        'IG', 'TT', 'NT', 'RMS',\n        'CFT', 'FWT', 'CAT', 'KDT', 'KCT',\n        'TBT', 'CBT', 'SBT', 'VBT', 'FBT', 'EBT', 'WBT', 'LBT',\n        'THT', 'CHT', 'SHT', 'VHT',\n        'BDT', 'TBO', 'CBO', 'SBO', 'VBO',\n        'ET', 'FET', 'HET', 'SDT', 'IEQ', 'FRT',\n        'T1T', 'T2T', 'T3T', 'T4T', 'T5T',\n        'MPT', 'KNT', 'WORD', 'NAME', 'NNAME', 'NM',\n        'RT', 'CIR', 'RUIR', 'RWIR',\n        'WIT', 'LIT', 'RIT', 'SIT', 'NRWT', 'NRUT', 'ARWT', 'ARUT',\n        'KET', 'TET', 'NST', 'RET', 'FAT', 'HRT', 'BLT',\n        'BUS', 'SHS', 'ASS', 'SUS', 'SCS', 'LAS', 'NES', 'COS', 'ENS', 'TOS',\n        'ABUS', 'ASHS', 'AASS', 'ASUS', 'ASCS', 'ALAS', 'ANES', 'ACOS', 'AENS', 'ATOS',\n        'SE', 'ARN', 'WEN', 'NEN', 'CEN', 'SEN', 'OEN',\n        'DFT',\n        'PNT', 'MLT',\n        'FDBT', 'GIFT', 'NWST', 'EKCT', 'KDHT', 'KDTT', 'CHVT', 'RITT', 'LIMT', 'UNCT', 'POET',\n        'KSET', 'DODT', 'INT1', 'INT2', 'GUCT', 'DEMT', 'WLDT', 'INHT', 'NIGT', 'RACT', 'RNCT',\n        'HBLT', 'POWT', 'NSET', 'ECBT', 'CUAT', 'CUMT', 'CUNT', 'WEAT', 'PAET', 'MEDT', 'REAT',\n        'HIST', 'PRET', 'LAPT', 'ORIT', 'ATRT', 'FAMT',\n        'FCNT', 'ASNT', 'TRMT', 'BEHT', 'DEST', 'NAMT', 'TTLT',\n        'CMNT', 'FPNT', 'CSRT', 'KSGT', 'DRET', 'DSET', 'DNNT', 'DNAT', 'HRET', 'HSET', 'HNNT',\n        'HNAT', 'MRET', 'MSET', 'MNNT', 'MNAT', 'EXIT', 'TRET', 'TSET', 'TNNT', 'TNAT', 'CABT',\n        'AJTA', 'AJTB', 'FOBT', 'KAET', 'KART', 'TEET', 'TERT', 'HKRT', 'EQDT', 'GART', 'FUET',\n        'RBLT', 'TKET', 'GPHT',\n        'TKNT1', 'TKNT2', 'TKNT3', 'GES', 'ORT'\n      )\n\n      def initialize(command)\n        super(command)\n\n        @sort_add_dice = true\n        @d66_sort_type = D66SortType::ASC\n        @round_type = RoundType::CEIL\n      end\n\n      def kiryoku_result(_total_n, dice_list, _diff)\n        num_6 = dice_list.count(6)\n\n        if num_6 == 0\n          \"\"\n        else\n          \" ＆ 《気力》\#{num_6}点獲得\"\n        end\n      end\n\n      def eval_game_system_specific_command(command)\n        output = \"\"\n        type = \"\"\n        total_n = \"\"\n\n        if (output = roll_tables(command, TABLES))\n          return output\n        elsif (output = roll_tables(command, A2Z_TABLES))\n          return output\n        elsif (output = roll_tables(command, RR236_TABLES))\n          return output\n        elsif (output = roll_tables(command, TK_TABLES))\n          return output\n        else\n\n          case command\n          when /^DFT(\\d*)$/i\n            feature_count = Regexp.last_match(1).to_i\n            return roll_device_factory_table(feature_count)\n\n          when /^NRWT/i\n            type = '基本レア武具アイテム'\n            total_n = @randomizer.roll_d66(D66SortType::NO_SORT)\n            output = mk_normal_rare_weapon_item_table(total_n)\n          when /^NRUT/i\n            type = '基本レア一般アイテム'\n            total_n = @randomizer.roll_d66(D66SortType::NO_SORT)\n            output = mk_normal_rare_item_table(total_n)\n          when /^ARWT/i\n            type = '上級レア武具アイテム'\n            total_n = @randomizer.roll_d66(D66SortType::NO_SORT)\n            output = mk_advanced_rare_weapon_item_table(total_n)\n          when /^ARUT/i\n            type = '上級レア一般アイテム'\n            total_n = @randomizer.roll_d66(D66SortType::NO_SORT)\n            output = mk_advanced_rare_item_table(total_n)\n          when /^CIR/i\n            type = 'コモンアイテムランダム決定'\n            total_n = @randomizer.roll_once(4)\n            output = mk_common_item_random_table(total_n)\n          when /^RWIR/i\n            type = 'レア武具アイテムランダム決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_rare_weapon_item_random_table(total_n)\n          when /^RUIR/i\n            type = 'レア一般アイテムランダム決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_rare_usual_item_random_table(total_n)\n          when /^NMAR/i\n            debug(\"namea passed\")\n            type = '芸術系名前'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_name_ar_table(total_n)\n          when /^NMFO/i\n            type = '食べ物系名前'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_name_fo_table(total_n)\n          when /^NMDN/i\n            type = '日用品系名前'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_name_dn_table(total_n)\n          when /^NMPL/i\n            type = '地名系名前'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_name_pl_table(total_n)\n          when /^NMMA/i\n            type = '機械系名前'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_name_ma_table(total_n)\n          when /^NMGO/i\n            type = '神様系名前'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_name_go_table(total_n)\n          when /^NNAME(\\d*)/i\n            type = '新名前'\n            count = getCount(Regexp.last_match(1))\n            names = \"\"\n            count.times do |_i|\n              name, dice = mk_new_name_table\n              names += \"[\#{dice}]\#{name} \"\n              output = names\n              total_n = count\n            end\n            output = output.strip\n          when /^RMS/i\n            type = 'ランダムマップ選択'\n            total_n = @randomizer.roll_d66(D66SortType::NO_SORT)\n            output = mk_random_map_select_table(total_n)\n\n          when /^KNT(\\d+)/i\n            type = '王国名決定'\n            count = getCount(Regexp.last_match(1))\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n\n            case count\n            when 1\n              output = mk_kingdom_name_1_table(total_n)\n            when 2\n              output = mk_kingdom_name_2_table(total_n)\n            when 3\n              output = mk_kingdom_name_3_table(total_n)\n            end\n\n          when /^KET/i\n            type = '王国環境'\n            total_n = @randomizer.roll_once(6)\n            output = mk_kingdom_environment_table(total_n)\n          when /^TET/i\n            type = '技術決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_technic_decide_table(total_n)\n          when /^NST/i\n            type = '国風決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_national_style_decide_table(total_n)\n          when /^RET/i\n            type = '資源決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_resource_decide_table(total_n)\n          when /^FAT/i\n            type = '施設決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_facility_decide_table(total_n)\n          when /^HRT/i\n            type = '人材決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_human_resources_decide_table(total_n)\n          when /^BLT/i\n            type = '血族決定'\n            total_n = @randomizer.roll_once(6)\n            output = mk_blood_decide_table(total_n)\n          when /^ABUS/i\n            type = '上級肉弾スキル'\n            output, total_n = mk_advanced_bullet_skill_table\n          when /^ASHS/i\n            type = '上級射撃スキル'\n            output, total_n = mk_advanced_shooting_skill_table\n          when /^AASS/i\n            type = '上級星術スキル'\n            output, total_n = mk_advanced_astrology_skill_table\n          when /^ASUS/i\n            type = '上級召喚スキル'\n            output, total_n = mk_advanced_summon_skill_table\n          when /^ASCS/i\n            type = '上級科学スキル'\n            output, total_n = mk_advanced_science_skill_table\n          when /^ALAS/i\n            type = '上級迷宮スキル'\n            output, total_n = mk_advanced_labyrinth_skill_table\n          when /^ANES/i\n            type = '上級交渉スキル'\n            output, total_n = mk_advanced_negotiation_skill_table\n          when /^ACOS/i\n            type = '上級便利スキル'\n            output, total_n = mk_advanced_convenient_skill_table\n          when /^AENS/i\n            type = '上級芸能スキル'\n            output, total_n = mk_advanced_entertainment_skill_table\n          when /^ATOS/i\n            type = '上級道具スキル'\n            output, total_n = mk_advanced_tool_skill_table\n          when /^GUCT/i\n            type = '守護星座'\n            total_n = @randomizer.roll_once(6) * 100 + @randomizer.roll_once(6) * 10 + @randomizer.roll_once(6)\n            output = mk_guardian_constellation_table(total_n)\n          when /^DEMT(\\d+)/i\n            type = '需要'\n            count = getCount(Regexp.last_match(1))\n            output, total_n = get_demand_table(count)\n          when /^RNCT(\\d*)/i\n            type = '人種名文字'\n            count = getCount(Regexp.last_match(1))\n            output, total_n = get_race_name_character_table(count)\n          when /^CUMT/i\n            type = '通貨材質'\n            @total = [@randomizer.roll_barabara(2, 6).sum(), @randomizer.roll_once(6)]\n            total_n = @total.join(',')\n            output = get_currency_material_table(*@total)\n          when /^CMNT/i\n            type = '組み合わせ系二つ名'\n            output, total_n = mk_combination_nickname_table\n          when /^DEST/i\n            type = '形容'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_descriptive_table(total_n)\n          when /^TRMT/i\n            type = '用語'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_terminology_table(total_n)\n          when /^BEHT/i\n            type = '行動'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_behavior_table(total_n)\n          when /^NAMT/i\n            type = '呼び名'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_rr236_name_table(total_n)\n          when /^TTLT/i\n            type = '称号'\n            total_n = @randomizer.roll_d66(D66SortType::ASC)\n            output = mk_title_table(total_n)\n          when /^EXIT([-+]?\\d*)/i\n            type = '遠征道中'\n            modify = get_modify(Regexp.last_match(1))\n            output, total_n = get_expedition_itinerary_table(modify)\n          end\n\n          if !output.nil?\n            debug(\"output\", output)\n            output = \"\#{type}表(\#{total_n}) ＞ \#{output}\"\n          else\n            super(command)\n          end\n        end\n      end\n    end\n  end\nend\nrequire \"bcdice/game_system/meikyu_kingdom_basic/item_table\"\nrequire \"bcdice/game_system/meikyu_kingdom_basic/kingdom_table\"\nrequire \"bcdice/game_system/meikyu_kingdom_basic/name_table\"\nrequire \"bcdice/game_system/meikyu_kingdom_basic/word_table\"\nrequire \"bcdice/game_system/meikyu_kingdom_basic/table\"\nrequire \"bcdice/game_system/meikyu_kingdom_basic/atoz_table\"\nrequire \"bcdice/game_system/meikyu_kingdom_basic/randr236_table\"\nrequire \"bcdice/game_system/meikyu_kingdom_basic/tk_table\"\n"], :names=>["<main>", "self", "require", "<module:BCDice>", "<module:GameSystem>", "<class:MeikyuKingdomBasic>", "register_prefix", "initialize", "command", "@sort_add_dice", "@d66_sort_type", "D66SortType::ASC", "D66SortType", "@round_type", "RoundType::CEIL", "RoundType", "kiryoku_result", "_total_n", "dice_list", "_diff", "num_6", "count", "6", "0", "eval_game_system_specific_command", "output", "type", "total_n", "roll_tables", "TABLES", "A2Z_TABLES", "RR236_TABLES", "TK_TABLES", "$ret_or_1", "feature_count", "Regexp", "last_match", "1", "to_i", "roll_device_factory_table", "@randomizer", "roll_d66", "D66SortType::NO_SORT", "mk_normal_rare_weapon_item_table", "mk_normal_rare_item_table", "mk_advanced_rare_weapon_item_table", "mk_advanced_rare_item_table", "roll_once", "4", "mk_common_item_random_table", "mk_rare_weapon_item_random_table", "mk_rare_usual_item_random_table", "debug", "mk_name_ar_table", "mk_name_fo_table", "mk_name_dn_table", "mk_name_pl_table", "mk_name_ma_table", "mk_name_go_table", "getCount", "names", "times", "block in eval_game_system_specific_command", "_i", "block (2 levels) in eval_game_system_specific_command", "mk_new_name_table", "name", "dice", "+", "strip", "mk_random_map_select_table", "mk_kingdom_name_1_table", "2", "mk_kingdom_name_2_table", "3", "mk_kingdom_name_3_table", "mk_kingdom_environment_table", "mk_technic_decide_table", "mk_national_style_decide_table", "mk_resource_decide_table", "mk_facility_decide_ta